      overlay.style.cssText = 'position:fixed;inset:0;background:rgba(6,8,14,.92);z-index:999999;display:flex;flex-direction:column;padding:calc(env(safe-area-inset-top,0px) + 16px) 16px calc(env(safe-area-inset-bottom,0px) + 16px);box-sizing:border-box;';
      var header = document.createElement('div');
      header.style.cssText = 'display:flex;align-items:center;justify-content:space-between;gap:12px;margin-bottom:12px;';
      var titleEl = document.createElement('div');
