      var frameWrap = document.createElement('div');
      frameWrap.style.cssText = 'flex:1;min-height:0;border-radius:16px;overflow:hidden;background:#0a0d14;border:1px solid rgba(255,255,255,.08);box-shadow:0 12px 32px rgba(0,0,0,.35);';
      var frame = document.createElement('iframe');
      frame.src = src;
      frame.title = title;
      frame.style.cssText = 'width:100%;height:100%;border:none;background:#fff;';
      function close() { overlay.remove(); }
      closeBtn2.onclick = close;
      overlay.onclick = function(e) { if (e.target === overlay) close(); };
      header.appendChild(titleEl);
      actionWrap.appendChild(openBtn);
