    // ===== 토스트 알림 함수 =====
    // ── 스크롤 맨위로 버튼 로직 ──────────────────────────────────
    (function () {
      function initScrollTopButtons() {
        // 저장목록 페이지 스크롤 감지
        const page1 = document.getElementById('page1');
        const savedBtn = document.getElementById('savedScrollTopBtn');
        if (page1 && savedBtn) {
          page1.addEventListener('scroll', function () {
            savedBtn.classList.toggle('visible', page1.scrollTop > 300);
          });
        }
        // 팝업 스크롤 감지
        const popBody = document.getElementById('popBody');
        const popBtn = document.getElementById('popupScrollTopBtn');
        if (popBody && popBtn) {
          popBody.addEventListener('scroll', function () {
            popBtn.classList.toggle('visible', popBody.scrollTop > 200);
          });
        }
      }
      // popup이 열릴 때마다 팝업 스크롤 버튼 재연결
      const _origOpenPopup = window.openPopup;
      if (typeof _origOpenPopup === 'undefined') {
        document.addEventListener('DOMContentLoaded', initScrollTopButtons);
      } else {
        initScrollTopButtons();
      }
      // DOMContentLoaded 후에도 실행
      if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', initScrollTopButtons);
      } else {
        setTimeout(initScrollTopButtons, 500);
      }
    })();

    function showToast(msg, type, duration) {
      const c = document.getElementById('toast-container');
      if (!c) return;
      // ★ 중복 방지
      const existing = c.querySelectorAll('.toast-msg');
      for (let i = 0; i < existing.length; i++) { if (existing[i].textContent === msg) return; }
      const el = document.createElement('div');
      el.className = 'toast-msg' + (type === 'ok' ? ' toast-ok' : type === 'warn' ? ' toast-warn' : '');
      el.textContent = msg;
      c.appendChild(el);
      const ms = duration || 3000;
      setTimeout(() => {
        el.classList.add('toast-fade');
        setTimeout(() => { if (el.parentNode) el.parentNode.removeChild(el); }, 450);
      }, ms);
    }

    // 지도 탭 카카오 키 입력 처리
    window._applyMapKakaoKey = function() {
      const el = document.getElementById('mapKakaoKeyInput');
      const v = el ? el.value.trim() : '';
      if (!v || v.length < 10) { alert('키를 입력해주세요'); return; }
      localStorage.setItem('kakao_api', v);
      document.getElementById('mapKakaoKeyDot').textContent = '🟡';
      // 카카오맵 SDK 로드
      if (!window.kakao || !window.kakao.maps) {
        const s = document.createElement('script');
        s.src = 'https://dapi.kakao.com/v2/maps/sdk.js?appkey=' + v + '&libraries=services,drawing&autoload=false';
        s.onload = () => { kakao.maps.load(() => { initMap(); document.getElementById('mapKakaoKeyDot').textContent = '🟢'; document.getElementById('kakaoKeyBanner').style.display='none'; }); };
        document.head.appendChild(s);
      } else {
        initMap();
        document.getElementById('mapKakaoKeyDot').textContent = '🟢';
        document.getElementById('kakaoKeyBanner').style.display='none';
      }
    };

    // 저장된 키 있으면 배너 숨기기
    (function() {
      const saved = localStorage.getItem('kakao_api');
      const el = document.getElementById('mapKakaoKeyInput');
      const dot = document.getElementById('mapKakaoKeyDot');
      if (saved && el) { el.value = saved; }
      if (saved && dot) { dot.textContent = '🟢'; }
      if (saved && document.getElementById('kakaoKeyBanner')) {
        // 키 있으면 배너 접어두기 (지도 로드 성공 시 자동 숨김)
      }
    })();

    // 카카오맵 동적 로드
    (function () {
      const loadKakaoMap = () => {
        const k = localStorage.getItem('kakao_api') || '4b907530560ea1d6425c25e09517efbf';
        if (!k || k.length < 10) return;
        if (window.kakao && window.kakao.maps) return;
        const s = document.createElement('script');
        s.type = 'text/javascript';
        s.src = 'https://dapi.kakao.com/v2/maps/sdk.js?appkey=' + k + '&libraries=services,drawing&autoload=false';
        s.onload = () => { if (window.kakao && window.kakao.maps) kakao.maps.load(() => { console.log('카카오맵 로드 완료'); if (typeof currentPage !== 'undefined' && currentPage === 2) initMap(); }); };
        document.head.appendChild(s);
      };
      if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', loadKakaoMap);
      else loadKakaoMap();
    })();

