      var header = document.createElement('div');
      header.style.cssText = 'display:flex;align-items:flex-start;justify-content:space-between;gap:12px;padding:18px 20px 14px;border-bottom:1px solid rgba(255,255,255,.08);';
      header.innerHTML = '<div><div style="font-size:16px;font-weight:800;color:var(--tx);">＋ 새 매물 직접 추가</div><div style="font-size:12px;color:var(--mu);margin-top:4px;">저장목록과 지도에서 바로 쓰는 수동 입력 매물입니다.</div></div>';
      var closeBtn = document.createElement('button');
      closeBtn.type = 'button';
      closeBtn.textContent = '✕';
      closeBtn.style.cssText = 'width:38px;height:38px;border:none;border-radius:999px;background:rgba(255,255,255,.08);color:#fff;font-size:18px;cursor:pointer;flex-shrink:0;';
      closeBtn.onclick = closeManualSavedModal;
      header.appendChild(closeBtn);

