          + field('사이트 유형', '<select id="manualSavedSource" style="width:100%;padding:11px 12px;background:var(--s2);border:1px solid var(--b1);border-radius:12px;color:var(--tx);font-size:13px;outline:none;"></select>', '출처 색상과 라벨이 이 값 기준으로 표시됩니다.')
          + field('거래 유형', '<select id="manualSavedDealKind" style="width:100%;padding:11px 12px;background:var(--s2);border:1px solid var(--b1);border-radius:12px;color:var(--tx);font-size:13px;outline:none;"><option value="sale">매매</option><option value="rent">임대</option><option value="unknown">기타</option></select>')
        + '</div>'
        + '<div style="grid-column:1/-1;">' + field('매물명', '<input id="manualSavedTitle" type="text" placeholder="예: 봉담 포르피아 1층 상가" style="width:100%;padding:12px 13px;background:var(--s2);border:1px solid var(--b1);border-radius:12px;color:var(--tx);font-size:14px;outline:none;">', '비워두면 주소와 유형으로 자동 제목을 만듭니다.') + '</div>'
        + '<div style="grid-column:1/-1;">' + field('주소', '<input id="manualSavedAddress" type="text" placeholder="예: 경기 화성시 효행로 123" style="width:100%;padding:12px 13px;background:var(--s2);border:1px solid var(--b1);border-radius:12px;color:var(--tx);font-size:14px;outline:none;">', '저장할 때 가능한 경우 자동으로 좌표를 잡습니다.') + '</div>'
        + field('매매가', '<input id="manualSavedPrice" type="text" inputmode="numeric" placeholder="만원 단위" style="width:100%;padding:11px 12px;background:var(--s2);border:1px solid var(--b1);border-radius:12px;color:var(--tx);font-size:13px;outline:none;">')
        + '<div id="manualSavedTradeMonthWrap">' + field('거래년월', '<input id="manualSavedTradeMonth" type="text" placeholder="예: 202604 / 2026-04 / 2026.04" style="width:100%;padding:11px 12px;background:var(--s2);border:1px solid var(--b1);border-radius:12px;color:var(--tx);font-size:13px;outline:none;">', '매매·실거래 추적용입니다. 저장 시 YYYY.MM 형식으로 맞춥니다.') + '</div>'
        + field('보증금', '<input id="manualSavedDeposit" type="text" inputmode="numeric" placeholder="만원 단위" style="width:100%;padding:11px 12px;background:var(--s2);border:1px solid var(--b1);border-radius:12px;color:var(--tx);font-size:13px;outline:none;">')
        + field('월세', '<input id="manualSavedRent" type="text" inputmode="numeric" placeholder="만원 단위" style="width:100%;padding:11px 12px;background:var(--s2);border:1px solid var(--b1);border-radius:12px;color:var(--tx);font-size:13px;outline:none;">')
        + field('면적', '<div style="display:grid;grid-template-columns:minmax(0,1fr) minmax(0,1fr);gap:8px;"><input id="manualSavedAreaM2" type="text" inputmode="decimal" placeholder="㎡" style="width:100%;padding:11px 12px;background:var(--s2);border:1px solid var(--b1);border-radius:12px;color:var(--tx);font-size:13px;outline:none;"><input id="manualSavedAreaPy" type="text" inputmode="decimal" placeholder="평" style="width:100%;padding:11px 12px;background:var(--s2);border:1px solid var(--b1);border-radius:12px;color:var(--tx);font-size:13px;outline:none;"></div>', '㎡ 또는 평 중 하나만 입력해도 자동 환산됩니다.')
        + field('층수', '<input id="manualSavedFloor" type="text" placeholder="예: 1층" style="width:100%;padding:11px 12px;background:var(--s2);border:1px solid var(--b1);border-radius:12px;color:var(--tx);font-size:13px;outline:none;">')
        + field('방향', '<input id="manualSavedDirection" type="text" placeholder="예: 남향" style="width:100%;padding:11px 12px;background:var(--s2);border:1px solid var(--b1);border-radius:12px;color:var(--tx);font-size:13px;outline:none;">')
        + field('매물 유형', '<input id="manualSavedPropType" type="text" placeholder="예: 상가 / 사무실 / 근린생활시설" style="width:100%;padding:11px 12px;background:var(--s2);border:1px solid var(--b1);border-radius:12px;color:var(--tx);font-size:13px;outline:none;">')
        + '<div style="grid-column:1/-1;">' + field('원본 링크', '<input id="manualSavedUrl" type="text" placeholder="https://..." style="width:100%;padding:12px 13px;background:var(--s2);border:1px solid var(--b1);border-radius:12px;color:var(--tx);font-size:13px;outline:none;">', '원본 사이트 링크가 있으면 함께 저장됩니다.') + '</div>'
        + '<div style="grid-column:1/-1;">' + field('메모', '<textarea id="manualSavedMemo" placeholder="현장 메모, 확인 포인트, 직접 입력 사유 등을 기록하세요." style="width:100%;min-height:120px;padding:12px 13px;background:var(--s2);border:1px solid var(--b1);border-radius:12px;color:var(--tx);font-size:13px;outline:none;resize:vertical;line-height:1.7;"></textarea>') + '</div>';

      var footer = document.createElement('div');
      footer.style.cssText = 'display:flex;align-items:center;justify-content:space-between;gap:10px;padding:14px 20px 18px;border-top:1px solid rgba(255,255,255,.08);';
      footer.innerHTML = '<div id="manualSavedStatus" style="font-size:11px;color:var(--mu);">저장하면 저장목록에 바로 추가됩니다.</div>';
      var btnWrap = document.createElement('div');
      btnWrap.style.cssText = 'display:flex;gap:8px;flex-shrink:0;';
      var cancelBtn = document.createElement('button');
      cancelBtn.type = 'button';
      cancelBtn.textContent = '취소';
      cancelBtn.style.cssText = 'height:42px;padding:0 16px;border-radius:12px;border:1px solid var(--b1);background:var(--s2);color:var(--mu);font-size:13px;cursor:pointer;';
      cancelBtn.onclick = closeManualSavedModal;
      var saveBtn = document.createElement('button');
      saveBtn.type = 'button';
      saveBtn.id = 'manualSavedSubmit';
      saveBtn.textContent = '저장';
      saveBtn.style.cssText = 'height:42px;padding:0 18px;border:none;border-radius:12px;background:linear-gradient(135deg,var(--ac),#6aa3ff);color:#08111f;font-size:13px;font-weight:800;cursor:pointer;';
      saveBtn.onclick = saveManualSavedItem;
      btnWrap.appendChild(cancelBtn);
