    // ===================================================
    // IndexedDB 지오코딩 캐시
    // ===================================================

    // DB 열기 (앱 시작 시 한 번만 호출)
    function openGeocodeDB() {
      return new Promise((resolve, reject) => {
        const req = indexedDB.open(GEOCODE_DB_NAME, GEOCODE_DB_VERSION);
        req.onupgradeneeded = function (e) {
          const db = e.target.result;
          if (!db.objectStoreNames.contains(GEOCODE_STORE)) {
            db.createObjectStore(GEOCODE_STORE); // key=주소문자열
          }
        };
        req.onsuccess = function (e) {
          geocodeDB = e.target.result;
          resolve(geocodeDB);
        };
        req.onerror = function (e) {
          console.error('IndexedDB 열기 실패', e);
          reject(e);
        };
      });
    }

    // 캐시에서 좌표 읽기
    function getCachedCoords(address) {
      return new Promise((resolve) => {
        if (!geocodeDB) { resolve(null); return; }
        try {
          const tx = geocodeDB.transaction(GEOCODE_STORE, 'readonly');
          const store = tx.objectStore(GEOCODE_STORE);
          const req = store.get(address);
          req.onsuccess = () => resolve(req.result || null);
          req.onerror = () => resolve(null);
        } catch (e) { resolve(null); }
      });
    }

    // 캐시에 좌표 저장
    function saveCachedCoords(address, lat, lng) {
      if (!geocodeDB) return;
      try {
        const tx = geocodeDB.transaction(GEOCODE_STORE, 'readwrite');
        const store = tx.objectStore(GEOCODE_STORE);
        store.put({ lat, lng }, address);
      } catch (e) { console.warn('캐시 저장 실패', e); }
    }

    // 캐시 통계 (저장된 주소 수)
    function getGeocodeDBCount() {
      return new Promise((resolve) => {
        if (!geocodeDB) { resolve(0); return; }
        try {
          const tx = geocodeDB.transaction(GEOCODE_STORE, 'readonly');
          const store = tx.objectStore(GEOCODE_STORE);
          const req = store.count();
          req.onsuccess = () => resolve(req.result || 0);
          req.onerror = () => resolve(0);
        } catch (e) { resolve(0); }
      });
    }

    // 캐시 초기화 (전체 삭제)
    window.clearGeocodeCache = async function () {
      if (!confirm('저장된 좌표 캐시를 모두 삭제하시겠습니까?\n다시 불러올 때 지오코딩을 처음부터 다시 합니다.')) return;
      if (!geocodeDB) return;
      try {
        const tx = geocodeDB.transaction(GEOCODE_STORE, 'readwrite');
        tx.objectStore(GEOCODE_STORE).clear();
        alert('캐시가 초기화되었습니다.');
      } catch (e) { alert('캐시 초기화 실패: ' + e.message); }
    }

    // 지오코딩 (캐시 우선 조회 → 없으면 API 호출 후 저장)
    async function geocodeWithCache(address) {
      const candidates = _buildMapAddressCandidates(address);
      if (!candidates.length) return null;
      const primaryKey = candidates[0];

      // 1) 캐시 먼저 확인 (정규화 주소 → 후보 주소 순)
      for (const key of candidates) {
        const cached = await getCachedCoords(key);
        if (cached && Number.isFinite(cached.lat) && Number.isFinite(cached.lng)) {
          if (key !== primaryKey) saveCachedCoords(primaryKey, cached.lat, cached.lng);
          return cached;
        }
      }

      // 2) 캐시 없으면 카카오 API 호출 (후보 주소 순차 재시도)
      return new Promise((resolve) => {
        if (!geocoder) { resolve(null); return; }
        const trySearch = function(idx) {
          if (idx >= candidates.length) { resolve(null); return; }
          const q = candidates[idx];
          geocoder.addressSearch(q, (result, status) => {
            if (status === kakao.maps.services.Status.OK && result.length > 0) {
              const lat = parseFloat(result[0].y);
              const lng = parseFloat(result[0].x);
              if (Number.isFinite(lat) && Number.isFinite(lng)) {
                saveCachedCoords(q, lat, lng);
                if (q !== primaryKey) saveCachedCoords(primaryKey, lat, lng);
                resolve({ lat, lng });
                return;
              }
            }
            trySearch(idx + 1);
          });
        };
        trySearch(0);
      });
    }

    // ===================================================
    // 실거래 저장 상태 UI 업데이트
    // ===================================================
    function updateCSVStorageStatus() {
      _applyTxApiOnlyUI();
      if (TX_API_ONLY_MODE) {
        try {
          const panelEl = document.getElementById('csvStatusPanel');
          if (panelEl) panelEl.style.display = 'none';
          const showBtn = document.getElementById('showTransactionBtn');
          if (showBtn) showBtn.disabled = false;
        } catch (e) {}
        return;
      }
      try {
        const raw = localStorage.getItem(CSV_RAW_STORAGE_KEY);
        const panelEl = document.getElementById('csvStatusPanel');
        const infoEl = document.getElementById('csvDataInfo');
        const showBtn = document.getElementById('showTransactionBtn');

        if (raw && transactionDataRaw.length > 0) {
          const count = transactionDataRaw.length;
          if (panelEl) {
            panelEl.style.display = 'block';
            panelEl.style.borderColor = '#119ded';
          }
          if (infoEl) {
            const sizeKB = Math.round(raw.length / 1024);
            infoEl.innerHTML = `<span style="color:#00d4aa;">💾 ${count.toLocaleString()}건</span><span style="font-size:10px;color:#6b7590;display:block;margin-top:2px;">자동저장됨 · ${sizeKB > 1024 ? (sizeKB / 1024).toFixed(1) + 'MB' : sizeKB + 'KB'}</span>`;
          }
          if (showBtn) showBtn.disabled = false;
        } else if (raw) {
          if (panelEl) {
            panelEl.style.display = 'block';
            panelEl.style.borderColor = '#119ded';
          }
          if (infoEl) {
            const sizeKB = Math.round(raw.length / 1024);
            infoEl.innerHTML = `<span style="color:#00d4aa;">💾 저장된 CSV 대기 중</span><span style="font-size:10px;color:#6b7590;display:block;margin-top:2px;">실거래 버튼을 누르면 로드 · ${sizeKB > 1024 ? (sizeKB / 1024).toFixed(1) + 'MB' : sizeKB + 'KB'}</span>`;
          }
          if (showBtn) showBtn.disabled = false;
        }
      } catch (e) { }
    }

    // CSV 저장 데이터 삭제
    window.clearSavedCSVData = function () {
      if (!confirm('저장된 CSV 실거래 데이터를 삭제하시겠습니까?\n다음에 다시 업로드해야 합니다.')) return;
      try {
        localStorage.removeItem(CSV_RAW_STORAGE_KEY);
        transactionDataRaw = [];
        const panelEl = document.getElementById('csvStatusPanel');
        const infoEl = document.getElementById('csvDataInfo');
        if (panelEl) panelEl.style.borderColor = '';
        if (infoEl) infoEl.textContent = '0건';
        document.getElementById('trade-status').textContent = 'CSV 데이터 삭제됨';
        alert('저장된 CSV 데이터가 삭제되었습니다.');
      } catch (e) { alert('삭제 실패: ' + e.message); }
    }

    // ===================================================
    // 지도 초기화
    // ===================================================

    // ===================================================
    // 커스텀 줌 슬라이더(카카오 기본 줌과 분리) - 1:1 레벨 매핑
    // - Kakao level: 1(최대 줌인) ~ 14(최대 줌아웃)
    // - UI는 CSS로만 반전(위=줌인처럼 보이게)하고, 값/로직은 그대로 둡니다.
    // ===================================================
    function clamp(v, min, max) { return Math.max(min, Math.min(max, v)); }

    function positionZoomSlider() { /* 도킹 레이아웃 사용: no-op */ }

    function syncZoomSlider() {
      if (!map) return;
      const range = document.getElementById('zoomRange');
      if (!range) return;
      const lv = map.getLevel();
      range.value = String(clamp(Math.round(lv), 1, 14));
    }

    function setupZoomSlider() {
      const slider = document.getElementById('mapZoomSlider');
      const range = document.getElementById('zoomRange');
      const btnPlus = document.getElementById('mzPlus');
      const btnMinus = document.getElementById('mzMinus');
      if (!slider || !range || !btnPlus || !btnMinus) return;

      // 초기 동기화
      syncZoomSlider();
      // (정석 구조) 도킹 레이아웃으로 배치하므로 위치 계산 불필요
      range.addEventListener('input', () => {
        if (!map) return;
        const lv = clamp(parseInt(range.value, 10), 1, 14);
        map.setLevel(lv, { animate: true });
      });

      btnPlus.addEventListener('click', () => {
        if (!map) return;
        const lv = map.getLevel();
        map.setLevel(clamp(Math.round(lv) - 1, 1, 14), { animate: true });
      });
      btnMinus.addEventListener('click', () => {
        if (!map) return;
        const lv = map.getLevel();
        map.setLevel(clamp(Math.round(lv) + 1, 1, 14), { animate: true });
      });
      // (정석 구조) resize 시에도 CSS 레이아웃이 처리
    }

    function initMap() {
      if (map) return; // 이미 초기화됨

      if (!window.kakao || !window.kakao.maps) {
        showToast('⚠️ 인사이트탭 ⚙️ 설정에서 Kakao JS Key를 입력하세요. 새로고침 없이 자동 적용됩니다.', 'warn');
        return;
      }

      const container = document.getElementById('map');
      try { container.style.touchAction = 'pan-x pan-y pinch-zoom'; } catch (e) {}
      const options = {
        center: new kakao.maps.LatLng(37.5665, 126.9780),
        level: 4,
        disableDoubleClickZoom: true,
        scrollwheel: true
      };

      map = new kakao.maps.Map(container, options);
      window.map = map; // ★ 전역 접근용 (상권분석, 온비드 마커 등)

      // ===================================================
      // 지도 뷰 상태 자동 저장/복원 (F5 새로고침 안전)
      // - center(level)만 복원 (마커/카드는 사용자가 '불러오기'로 제어)
      // ===================================================
      try {
        const raw = localStorage.getItem('map_view_state_v1');
        if (raw) {
          const st = JSON.parse(raw);
          if (st && st.lat && st.lng) {
            map.setCenter(new kakao.maps.LatLng(st.lat, st.lng));
          }
          if (st && typeof st.level === 'number') {
            map.setLevel(st.level);
          }
        }
      } catch (e) { }

      // idle(이동/줌 종료) 시 현재 상태 저장
      try {
        kakao.maps.event.addListener(map, 'idle', () => {
          try {
            const c = map.getCenter();
            const st = { lat: c.getLat(), lng: c.getLng(), level: map.getLevel(), t: Date.now() };
            localStorage.setItem('map_view_state_v1', JSON.stringify(st));
          } catch (e) { }
        });
      } catch (e) { }

      // ★ 카드 드래그 시 지도 드래그 방지
      // 카카오맵은 자체 이벤트 레이어에서 드래그를 감지하므로,
      // 지도 컨테이너에 캡처 단계(useCapture:true) pointerdown을 걸어
      // 클릭 대상이 map-card 내부면 지도가 드래그를 선점하지 못하게 막는다.
      container.addEventListener('pointerdown', function (e) {
        if (e.target.closest('.map-card')) {
          e.stopPropagation();
        }
      }, true); // true = 캡처 단계 (카카오맵보다 먼저 실행)

      // 🎯 반경 검색 UI 바인딩 + 지도 클릭 핀포인트
      try { initRadiusUIBindings(); } catch (e) { console.warn('initRadiusUIBindings error:', e); }
      kakao.maps.event.addListener(map, 'click', function (mouseEvent) {
        const chk = document.getElementById('chkPickPin');
        // 직접지정 체크박스가 켜져 있을 때만 처리
        if (!chk || !chk.checked) return;

        const latlng = mouseEvent.latLng;

        // areaModeMini + areaMode 둘 다 radius로 전환
        document.querySelectorAll('input[name="areaModeMini"]').forEach(r => { r.checked = (r.value === 'radius'); });
        document.querySelectorAll('input[name="areaMode"]').forEach(r => { r.checked = (r.value === 'radius'); });
        areaSearchMode = 'radius';

        // 반경 opts 패널 표시
        const opts = document.getElementById('areaMiniRadiusOpts');
        if (opts) opts.style.display = 'flex';

        // 기준점 설정 + 원 표시
        setRadiusCenter(latlng, false);
        updateRadiusCircle();

        // 직접지정 체크박스 해제 + 커서/스타일 복원
        chk.checked = false;
        if (typeof window._applyPickPinUI === 'function') window._applyPickPinUI(false);

        showToast('📍 기준점이 설정됐습니다. 이제 매물을 불러오세요', 'ok');
      });


      // 줌 변경 시 슬라이더 동기화
      kakao.maps.event.addListener(map, 'zoom_changed', () => {
        syncZoomSlider();
        if (window._resetSpreadState) window._resetSpreadState();
      });

      // 커스텀 줌 슬라이더 초기화(카카오 기본 줌 UI와 별개)
      setupZoomSlider();

      // ✅ 카카오 기본 줌 컨트롤 사용 (커스텀 줌 UI 제거)
      try {
        const _zoomCtrl = new kakao.maps.ZoomControl();
        map.addControl(_zoomCtrl, kakao.maps.ControlPosition.RIGHT);
      } catch (e) { }
      geocoder = new kakao.maps.services.Geocoder();
      ps = new kakao.maps.services.Places();
      window.geocoder = geocoder;
      window.ps = ps;
      _syncMapInfraRefs();

      // 로드뷰 초기화
      const rvContainer = document.getElementById('roadview');
      rv = new kakao.maps.Roadview(rvContainer);
      rvClient = new kakao.maps.RoadviewClient();

      // 미니맵 초기화
      const miniContainer = document.getElementById('minimap');
      minimap = new kakao.maps.Map(miniContainer, { center: map.getCenter(), level: 2 });

      kakao.maps.event.addListener(minimap, 'click', function (mouseEvent) { if (mouseEvent && mouseEvent.latLng) openRoadviewAtPos(mouseEvent.latLng); });

      // ★ 미니맵 방향 화살표 오버레이 생성
      const arrowWrap = document.createElement('div');
      arrowWrap.id = 'minimap-arrow-wrap';
      arrowWrap.innerHTML = `<svg width="20" height="20" viewBox="0 0 20 20" style="overflow:visible;filter:drop-shadow(0 1px 3px rgba(0,0,0,0.6));">
    <polygon points="10,1 17,16 10,13 3,16" fill="#ff4444" stroke="white" stroke-width="1.5" stroke-linejoin="round"/>
  </svg>`;
      miniContainer.appendChild(arrowWrap);

      // ★ 미니맵 로드뷰 방향 업데이트 함수 (pan 각도로 화살표 회전)
      window.updateMinimapArrow = function (pan) {
        const wrap = document.getElementById('minimap-arrow-wrap');
        if (wrap) wrap.style.transform = `translate(-50%,-50%) rotate(${pan}deg)`;
      };

      // Drawing manager 초기화 (거리측정용)
      drawingManager = new kakao.maps.drawing.DrawingManager({
        map: map,
        drawingMode: [kakao.maps.drawing.OverlayType.POLYLINE]
      });

      // 로드뷰 마커 생성 (방향 화살표)
      const rvMarkerContent = `<div class="roadview-marker"><svg class="roadview-arrow" width="52" height="52" viewBox="0 0 52 52" xmlns="http://www.w3.org/2000/svg"><defs><radialGradient id="rvbg" cx="40%" cy="30%" r="65%"><stop offset="0%" stop-color="#72c8ff"/><stop offset="55%" stop-color="#1a7fcc"/><stop offset="100%" stop-color="#0a3d6b"/></radialGradient><filter id="rvsh"><feGaussianBlur in="SourceAlpha" stdDeviation="1.5" result="b"/><feOffset dx="1" dy="2" result="ob"/><feMerge><feMergeNode in="ob"/><feMergeNode in="SourceGraphic"/></feMerge></filter></defs><ellipse cx="26" cy="49" rx="11" ry="3.5" fill="rgba(0,0,0,0.35)"/><circle cx="26" cy="23" r="20" fill="url(#rvbg)" filter="url(#rvsh)" stroke="rgba(255,255,255,0.25)" stroke-width="1"/><ellipse cx="20" cy="16" rx="8" ry="5" fill="rgba(255,255,255,0.28)" transform="rotate(-20,20,16)"/><polygon points="26,5 34,20 26,17 18,20" fill="rgba(255,255,255,0.95)"/><circle cx="26" cy="23" r="4" fill="#00e676" stroke="white" stroke-width="1.5"/><path d="M22,41 Q26,52 30,41" fill="url(#rvbg)"/></svg></div>`;
      roadviewMarker = new kakao.maps.CustomOverlay({
        content: rvMarkerContent,
        position: map.getCenter(),
        yAnchor: 0.5,
        zIndex: 100
      });

      // 지도 이벤트
      kakao.maps.event.addListener(map, 'idle', refreshMapView);
      document.addEventListener('keydown', function (e) {
        if (e.key === 'Escape') {
          const rv = document.getElementById('roadview-box'); if (rv && rv.style.display === 'block') { closeRoadview(); return; } const pop = document.getElementById('popup'); if (pop && pop.classList.contains('on')) { closePopup(); return; }
          // ★ [v249] 지도탭 팝업 ESC 닫기
          const captureModal = document.getElementById('mapCaptureModal'); if (captureModal && captureModal.style.display !== 'none') { captureModal.style.display = 'none'; if (typeof _clearCapturePreview === 'function') _clearCapturePreview(); return; }
          const aiPanel = document.getElementById('aiMapPanel'); if (aiPanel && aiPanel.style.display !== 'none') { if (typeof closeAiMapPanel === 'function') closeAiMapPanel(); return; }
          const calcPanel = document.getElementById('calcPanel'); if (calcPanel && calcPanel.style.display !== 'none') { if (typeof closeCalcPanel === 'function') closeCalcPanel(); return; }
          const kcardDetailModal = document.getElementById('kcardDetailModal');
          if (kcardDetailModal && kcardDetailModal.style.display !== 'none') { if (typeof closeKcardDetail === 'function') closeKcardDetail(); else kcardDetailModal.style.display = 'none'; return; }
          const kcardModal = document.getElementById('kcardModal'); if (kcardModal && kcardModal.style.display !== 'none') { kcardModal.style.display = 'none'; return; }
          const addSiteModal = document.getElementById('addSiteModal'); if (addSiteModal && addSiteModal.style.display !== 'none') { addSiteModal.style.display = 'none'; return; }
          const sbizReport = document.getElementById('sbizReportModal'); if (sbizReport) { sbizReport.remove(); return; }
          // 스냅샷 관련 팝업 ESC 닫기
          const swDelPop = document.getElementById('_swDelPop'); if (swDelPop) { swDelPop.remove(); return; }
          // 동적으로 생성된 작업룸 저장 팝업 (fixed, z-index:99999)
          const dynPops = document.querySelectorAll('div[style*="z-index:99999"][style*="position:fixed"]');
          if (dynPops.length) { dynPops[dynPops.length - 1].remove(); return; }
        }
      });
      kakao.maps.event.addListener(map, 'zoom_changed', function () {
        const currentZoom = map.getLevel();
        // 줌 레벨이 2단계 이상 변경되었을 때만 임시 배율 리셋
        if (lastZoomLevel !== null && Math.abs(currentZoom - lastZoomLevel) >= 2) {
          manualScale = 1.0;
          const slider = document.getElementById('manualCardScale');
          const label = document.getElementById('manualScaleLabel');
          if (slider) slider.value = 100;
          if (label) label.textContent = '100%';
        }

        lastZoomLevel = currentZoom;
        adjustCardSizeByZoom();
        refreshMapView();
      });
      kakao.maps.event.addListener(map, 'center_changed', updateRoadviewDirection);

      // 지도 이동 시 임시 배율은 유지 (드래그로는 리셋하지 않음)
      kakao.maps.event.addListener(map, 'dragend', function () {
        // dragend 시에는 임시 배율을 리셋하지 않음
        // 사용자가 수동으로 조정한 배율은 그대로 유지
        // ★ [FIX] 카드 방사형 펼치기 상태 해제 (지도 이동 시 카드-마커 위치 어긋남 방지)
        if (window._resetSpreadState) window._resetSpreadState();
      });

      // 저장된 메모 로드
      setTimeout(() => loadMemos(), 100);

      // IndexedDB 열기 (지오코딩 캐시)
      openGeocodeDB().then(async () => {
        const count = await getGeocodeDBCount();
        if (count > 0) {
          document.getElementById('trade-status').textContent = `좌표 캐시 ${count.toLocaleString()}건 준비됨`;
        }
        updateCSVStorageStatus();
        // 내장 CSV 데이터 자동 로드 (IndexedDB 준비 후 실행)
        initExternalCSVDatasets();
      }).catch(() => {
        console.warn('IndexedDB를 사용할 수 없습니다. 캐시 없이 동작합니다.');
        updateCSVStorageStatus();
        initExternalCSVDatasets(); // IndexedDB 없어도 데이터는 로드
      });

      refreshMapView();

      // ★ 우클릭 컨텍스트 메뉴
      kakao.maps.event.addListener(map, 'rightclick', function (mouseEvent) {
        if (window.measureMode) return;
        const latlng = mouseEvent.latLng;
        window._ctxLat = latlng.getLat();
        window._ctxLng = latlng.getLng();
        _showMapCtxMenu(mouseEvent.point.x, mouseEvent.point.y);
      });
      kakao.maps.event.addListener(map, 'click', _hideMapCtxMenu);
      kakao.maps.event.addListener(map, 'click', function () { _removeSearchPin(); });
      kakao.maps.event.addListener(map, 'dragstart', _hideMapCtxMenu);
      document.addEventListener('click', function (e) {
        const m = document.getElementById('mapContextMenu');
        if (m && !m.contains(e.target)) _hideMapCtxMenu();
      });
    }

    // =====================================================
    // ★ 우클릭 컨텍스트 메뉴
    // =====================================================
    function _formatMapContextAddressResult(result) {
      const r = Array.isArray(result) && result.length ? result[0] : null;
      if (!r) return '';
      const road = String(r.road_address && r.road_address.address_name || '').trim();
      const jibun = String(r.address && r.address.address_name || '').trim();
      return road ? road + (jibun ? ' (' + jibun + ')' : '') : jibun;
    }

    function _ensureMapContextGeocoder() {
      if (!window.geocoder && window.kakao && window.kakao.maps && window.kakao.maps.services) {
        try { window.geocoder = new kakao.maps.services.Geocoder(); } catch (e) {}
      }
      return window.geocoder && typeof window.geocoder.coord2Address === 'function' ? window.geocoder : null;
    }

    function _resolveMapContextAddress(lat, lng) {
      const currentAddr = _getCleanContextAddress();
      if (currentAddr) return Promise.resolve(currentAddr);
      const gc = _ensureMapContextGeocoder();
      if (!gc || !Number.isFinite(Number(lat)) || !Number.isFinite(Number(lng))) return Promise.resolve('');
      return new Promise(resolve => {
        try {
          gc.coord2Address(Number(lng), Number(lat), function (result, status) {
            if (status === kakao.maps.services.Status.OK && result && result.length) {
              const addr = _formatMapContextAddressResult(result);
              const addrEl = document.getElementById('ctxAddrText');
              if (addrEl && addr) addrEl.textContent = addr;
              resolve(_getCleanContextAddress() || String(addr || '').replace(/\s*\([^)]*\)\s*$/, '').trim());
            } else {
              resolve('');
            }
          });
        } catch (e) {
          resolve('');
        }
      });
    }

    function _showMapCtxMenu(canvasX, canvasY) {
      const menu = document.getElementById('mapContextMenu');
      if (!menu) return;
      const lat = window._ctxLat, lng = window._ctxLng;
      document.getElementById('ctxCoordText').textContent =
        `${lat.toFixed(5)},  ${lng.toFixed(5)}`;
      // 주소 조회
      const addrRow = document.getElementById('ctxAddrRow');
      const addrEl = document.getElementById('ctxAddrText');
      if (addrRow && addrEl) {
        addrRow.style.display = '';
        addrEl.textContent = '주소 조회 중...';
        // geocoder 없으면 즉시 초기화 시도
        _ensureMapContextGeocoder();
        function _doAddr() {
          const gc = _ensureMapContextGeocoder();
          if (gc) {
            gc.coord2Address(lng, lat, function (result, status) {
              if (status === kakao.maps.services.Status.OK && result && result.length) {
                addrEl.textContent = _formatMapContextAddressResult(result) || '주소 없음';
              } else {
                addrEl.textContent = '주소를 찾을 수 없습니다';
              }
            });
          } else {
            addrEl.textContent = '주소 서비스를 이용할 수 없습니다 (카카오 API 키 확인)';
          }
        }
        if (_ensureMapContextGeocoder()) {
          _doAddr();
        } else {
          // 카카오 SDK 로드 완료 대기 후 1회 재시도
          setTimeout(function () {
            _ensureMapContextGeocoder();
            _doAddr();
          }, 800);
        }
      }
      // 출발지 설정된 경우 라벨 갱신
      _updateCtxWalkLabels();
      const mapEl = document.getElementById('map');
      const rect = mapEl ? mapEl.getBoundingClientRect() : { left: 0, top: 0 };
      let x = rect.left + canvasX, y = rect.top + canvasY;
      menu.style.display = 'block';
      requestAnimationFrame(() => {
        const mw = menu.offsetWidth || 240, mh = menu.offsetHeight || 300;
        if (x + mw > window.innerWidth - 8) x = window.innerWidth - mw - 8;
        if (y + mh > window.innerHeight - 8) y = window.innerHeight - mh - 8;
        if (x < 8) x = 8; if (y < 8) y = 8;
        menu.style.left = x + 'px'; menu.style.top = y + 'px';
      });
    }
    function _hideMapCtxMenu() {
      const m = document.getElementById('mapContextMenu');
      if (m) m.style.display = 'none';
    }
    function _updateCtxWalkLabels() {
      const hasStart = !!(window._walkStartLat);
      const hasEnd = !!(window._walkEndLat);
      const sl = document.getElementById('ctxWalkStartLabel');
      const ss = document.getElementById('ctxWalkStartSub');
      const el = document.getElementById('ctxWalkEndLabel');
      const es = document.getElementById('ctxWalkEndSub');
      if (sl) sl.textContent = hasStart
        ? `출발지 변경 (현재: ${window._walkStartLat.toFixed(4)}, ${window._walkStartLng.toFixed(4)})`
        : '출발지로 설정';
      if (ss) ss.textContent = hasStart ? '다시 클릭하면 변경됩니다' : '도보 경로의 출발 위치';
      if (el) el.textContent = hasEnd
        ? `도착지 변경 (현재: ${window._walkEndLat.toFixed(4)}, ${window._walkEndLng.toFixed(4)})`
        : '도착지로 설정 + 네이버 열기';
      if (es) es.textContent = hasStart && !hasEnd
        ? '클릭 시 바로 네이버 경로 열기'
        : hasEnd ? '다시 클릭하면 변경됩니다' : '출발지가 있으면 바로 경로 열기';
    }

    // 네이버 지도 건물정보
    function ctxNaverBuilding() {
      _hideMapCtxMenu();
      const lat = window._ctxLat, lng = window._ctxLng;
      if (lat == null) return;
      window.open(`https://map.naver.com/p/?c=${lng},${lat},17,0,0,0,dh`, '_blank');
      showToast('네이버 지도가 열렸습니다. 건물을 클릭하면 상세정보를 확인할 수 있습니다.', 'ok', 4000);
    }
    window.ctxNaverBuilding = ctxNaverBuilding;
    // 네이버 부동산 상가매물
    function ctxNaverLand() {
      _hideMapCtxMenu();
      const lat = window._ctxLat, lng = window._ctxLng;
      if (lat == null) return;
      window.open(`https://new.land.naver.com/offices?ms=${lat},${lng},19&a=SG:SMS:APTHGJ&e=RETAIL&ad=true`, '_blank');
      showToast('네이버 부동산 상가매물 페이지가 열렸습니다.', 'ok');
    }
    window.ctxNaverLand = ctxNaverLand;

    function _getCleanContextAddress() {
      const addrEl = document.getElementById('ctxAddrText');
      const raw = addrEl ? String(addrEl.textContent || '').trim() : '';
      if (!raw || raw.includes('조회 중') || raw.includes('주소 없음')) return '';
      return raw.replace(/\s*\([^)]*\)\s*$/, '').trim();
    }

    function _copyTextForExternalOpen(text, doneMsg) {
      const str = String(text || '').trim();
      if (!str) return false;
      if (typeof window.wr2CopyText === 'function') {
        window.wr2CopyText(str, doneMsg || '주소를 복사했습니다');
        return true;
      }
      try {
        if (navigator.clipboard && navigator.clipboard.writeText) {
          navigator.clipboard.writeText(str).catch(() => {});
          if (typeof showToast === 'function') showToast(doneMsg || '주소를 복사했습니다', 'ok');
          return true;
        }
      } catch (e) {}
      try {
        const ta = document.createElement('textarea');
        ta.value = str;
        ta.style.position = 'fixed';
        ta.style.opacity = '0';
        document.body.appendChild(ta);
        ta.focus();
        ta.select();
        document.execCommand('copy');
        document.body.removeChild(ta);
        if (typeof showToast === 'function') showToast(doneMsg || '주소를 복사했습니다', 'ok');
        return true;
      } catch (e2) {
        return false;
      }
    }

    async function ctxOpenExternalService(site) {
      const key = String(site || '').toLowerCase();
      const lat = Number(window._ctxLat);
      const lng = Number(window._ctxLng);
      const hasCoord = Number.isFinite(lat) && Number.isFinite(lng);
      const popup = window.open('about:blank', '_blank');
      _hideMapCtxMenu();
      const addr = await _resolveMapContextAddress(lat, lng);

      const encodedAddr = encodeURIComponent(String(addr || '').trim());
      const encodedCoord = hasCoord ? `${lat.toFixed(6)},${lng.toFixed(6)}` : '';
      const config = {
        jumpo: {
          label: '점포라인',
          url: hasCoord
            ? `https://map.jumpoline.com/viewmap.asp?locDaX=${lng.toFixed(6)}&locDaY=${lat.toFixed(6)}&Page=1`
            : 'https://map.jumpoline.com/main',
          copyAddress: !hasCoord || !!addr
        },
        assa: {
          label: '아싸점포',
          url: hasCoord
            ? `https://xn--v69ap5so3hsnb81e1wfh6z.com/map?lat=${lat.toFixed(6)}&lng=${lng.toFixed(6)}${encodedAddr ? `&q=${encodedAddr}` : ''}`
            : `https://xn--v69ap5so3hsnb81e1wfh6z.com/map${encodedAddr ? `?q=${encodedAddr}` : ''}`,
          copyAddress: true
        },
        nemo: {
          label: '네모',
          url: hasCoord
            ? `https://www.nemoapp.kr/store?lat=${lat.toFixed(6)}&lng=${lng.toFixed(6)}${encodedAddr ? `&q=${encodedAddr}` : ''}`
            : `https://www.nemoapp.kr/store${encodedAddr ? `?q=${encodedAddr}` : ''}`,
          copyAddress: true
        },
        disco: {
          label: '디스코',
          url: hasCoord
            ? `https://www.disco.re/map?lat=${lat.toFixed(6)}&lng=${lng.toFixed(6)}&zoom=17${encodedAddr ? `&q=${encodedAddr}` : ''}`
            : `https://www.disco.re${encodedAddr ? `?q=${encodedAddr}` : ''}`,
          copyAddress: !hasCoord || !!addr
        },
        bds: {
          label: '플래닛',
          url: hasCoord
            ? `https://www.bdsplanet.com/map/realprice_map.ytp?lat=${lat.toFixed(6)}&lng=${lng.toFixed(6)}&zoom=17${encodedAddr ? `&q=${encodedAddr}` : ''}`
            : `https://www.bdsplanet.com/map/realprice_map.ytp${encodedAddr ? `?q=${encodedAddr}` : ''}`,
          copyAddress: true
        }
      };
      const cfg = config[key];
      if (!cfg) return;

      if (cfg.copyAddress) {
        const copyValue = addr || (encodedCoord ? encodedCoord.replace(',', ', ') : '');
        _copyTextForExternalOpen(copyValue, addr ? `${cfg.label}용 주소를 복사했습니다` : `${cfg.label}용 좌표를 복사했습니다`);
      }

      try {
        if (popup) popup.location.href = cfg.url;
        else window.open(cfg.url, '_blank');
        showToast(
          (cfg.copyAddress && (addr || hasCoord))
            ? `${cfg.label}를 열었습니다. 복사된 주소/좌표를 붙여넣으세요.`
            : `${cfg.label}를 열었습니다.`,
          'ok',
          3500
        );
      } catch (e) {
        showToast(`${cfg.label} 열기에 실패했습니다.`, 'warn');
      }
    }
