      window._walkStartLat = lat; window._walkStartLng = lng;
      // 기존 출발지 마커 제거 후 새로 생성
      if (_walkStartTempMarker) { _walkStartTempMarker.setMap(null); _walkStartTempMarker = null; }
      _walkStartTempMarker = _createWalkTempMarker(lat, lng, '#4f8eff');
      _updateWalkPanel();
      showToast(`🟦 출발지 설정: ${lat.toFixed(4)}, ${lng.toFixed(4)}`, 'ok');
      document.getElementById('walkRoutePanel').classList.add('show');
