    // ── 마커 Ctrl+Z 되돌리기 ─────────────────────────────────────
    const _markerUndoStack = [];
    let _markerDragUndoPos = null; // ★ 드래그 시작 위치 임시 저장

    function undoLastMarker() {
      if (!_markerUndoStack.length) { showToast('⏪ 되돌릴 마커가 없습니다', 'warn'); return; }
      const last = _markerUndoStack.pop();

      // ★ 드래그 이동 undo: 마커를 이전 위치로 복원
      if (last.type === 'drag') {
        try {
          last.marker.setPosition(last.prevPos);
          if (last.overlay) last.overlay.setPosition(last.prevPos);
          // stackKey 갱신
          const ov = (mapOverlays || []).find(o => o.id === last.id);
          if (ov) {
            ov.stackKey = `${last.prevPos.getLat().toFixed(6)}_${last.prevPos.getLng().toFixed(6)}`;
          }
          updateMapLine(last.id);
          updateStackedCards();
          showToast(`⏪ 드래그 이동 취소: ${last.item.data?.소재지 || last.id}`, 'ok');
        } catch (e) { showToast('⏪ 이동 취소 실패', 'warn'); }
        return;
      }

      // ★ 마커 추가 undo: 마커 삭제
      try { last.marker.setMap(null); } catch (e) { }
      try { last.overlay.setMap(null); } catch (e) { }
      window.mapMarkers = (window.mapMarkers || []).filter(m => m.id !== last.id);
      mapOverlays = (mapOverlays || []).filter(m => m.id !== last.id);
      loadedMarkerIds.delete(last.id);
      updateFilterCounts();
      updateStackedCards();
      showToast(`⏪ 마커 되돌리기: ${last.item.data?.소재지 || last.id}`, 'ok');
    }


    // ===================================================
    // 카드 자동 배치 - 단순 고정 위치
    // ===================================================
    // ★ [v165] 반경 모드 카드 배치 시 인덱스 기반 분산을 위한 카운터
    let _autoCardPlaceIdx = 0;
    function resetAutoCardIdx() { _autoCardPlaceIdx = 0; }

    function getAutoCardPosition(markerPos) {
      // ★ 반경 모드: 마커에서 반경 중심 반대 방향으로 카드 배치 (반경 바깥)
      // + 인덱스 기반 오프셋으로 겹침 방지
      if (getAreaSearchMode && getAreaSearchMode() === 'radius' && radiusCenterLatLng && markerPos) {
        try {
          const cx = map.getProjection().containerPointFromCoords(radiusCenterLatLng);
          const mx = map.getProjection().containerPointFromCoords(markerPos);
          // 마커 → 반경 중심 방향 벡터
          const dx = mx.x - cx.x;
          const dy = mx.y - cx.y;
          const dist = Math.sqrt(dx * dx + dy * dy) || 1;

          // 바깥 방향 기본 거리
          const baseDist = 130;
          // 인덱스 기반 추가 오프셋: 같은 방향에 카드가 쌓이지 않도록 지그재그
          const idx = _autoCardPlaceIdx++;
          const spread = (idx % 3) * 50 - 50; // -50, 0, +50 순환
          const layerOffset = Math.floor(idx / 3) * 60; // 3개마다 한 층씩 더 밀어냄

          // 수직 방향(법선) 벡터로 좌우 분산
          const perpX = -dy / dist;
          const perpY = dx / dist;

          const outX = (dx / dist) * (baseDist + layerOffset) + perpX * spread;
          const outY = (dy / dist) * (baseDist + layerOffset) + perpY * spread;

          return {
            left: Math.round(outX),
            top: Math.round(outY - 80)
          };
        } catch (e) { /* fallthrough */ }
      }
      // 기본: 마커 오른쪽 위에 고정 배치
      return {
        left: 30,
        top: -140
      };
    }


