    // v52: 🧲 결합 픽 모드 (마커 클릭으로 결합)
    // ===================================================
    let _mergePickMode = false;
    let _mergeSourceId = null;

    function mergeCardToNearest(sourceId) {
      if (_mergePickMode) {
        cancelMergePick();
        return;
      }
      _mergeSourceId = sourceId;
      _mergePickMode = true;
      const mapEl = document.getElementById('map');
      if (mapEl) mapEl.style.cursor = 'crosshair';
      showToast('🧲 결합할 마커를 클릭하세요 (ESC 취소)', 'warn');

      // ESC 취소
      function onEsc(e) {
        if (e.key === 'Escape') {
          cancelMergePick();
          document.removeEventListener('keydown', onEsc);
        }
      }
      document.addEventListener('keydown', onEsc);
    }

    function cancelMergePick() {
      _mergePickMode = false;
      _mergeSourceId = null;
      const mapEl = document.getElementById('map');
      if (mapEl) mapEl.style.cursor = '';
      showToast('결합 취소', 'warn');
    }

    function handleMergePickClick(clickedId) {
      if (!_mergePickMode) return false;
      if (clickedId === _mergeSourceId) {
        showToast('자기 자신과는 결합할 수 없어요', 'warn');
        return true;
      }

      const self = mapOverlays.find(o => o.id === _mergeSourceId);
      const target = mapOverlays.find(o => o.id === clickedId);
      if (!self || !self.marker || !target || !target.marker) {
        cancelMergePick();
        return true;
      }

      const targetPos = target.marker.getPosition();
      const newKey = `${targetPos.getLat().toFixed(6)}_${targetPos.getLng().toFixed(6)}`;

      try { self.marker.setPosition(targetPos); } catch (_) { }
      try { if (self.overlay) self.overlay.setPosition(targetPos); } catch (_) { }
      self.stackKey = newKey;

      _mergePickMode = false;
      _mergeSourceId = null;
      const mapEl = document.getElementById('map');
      if (mapEl) mapEl.style.cursor = '';

      updateStackedCards();

      // 결합 flash 애니메이션
      [self.id, clickedId].forEach(eid => {
        const el = document.getElementById(eid);
        if (el) {
          el.classList.remove('merge-flash');
          void el.offsetWidth;
          el.classList.add('merge-flash');
          setTimeout(() => el.classList.remove('merge-flash'), 650);
        }
      });
      showToast('🧲 결합 완료!', 'ok');
      return true;
    }

