    function loadAutoBriefing() {
      try {
        const clips = (window._idbCache && window._idbCache['news_auto_clips'] || []);
        if (!clips.length) return;
        const latest = clips[0];
        const banner = document.getElementById('autoBriefingBanner');
        if (!banner) return;
        banner.style.display = 'block';
        const dateEl = document.getElementById('autoBriefDate');
        if (dateEl) dateEl.textContent = latest.date || '';
        const sentEl = document.getElementById('autoBriefSentiment');
        if (sentEl) {
          const s = latest.sentiment || latest.analysis?.market_sentiment || '중립';
          const cfg = { 긍정: { bg: 'rgba(17,157,237,0.15)', c: '#119ded', e: '📈' }, 부정: { bg: 'rgba(255,77,77,0.12)', c: '#ff4d4d', e: '📉' }, 혼재: { bg: 'rgba(255,140,66,0.12)', c: '#ff8c42', e: '↔️' }, 중립: { bg: 'rgba(107,117,144,0.12)', c: '#6b7590', e: '➖' } };
          const st = cfg[s] || cfg['중립'];
          sentEl.style.cssText = `background:${st.bg};color:${st.c};border:1px solid ${st.c};font-size:10px;font-weight:700;padding:1px 8px;border-radius:10px;`;
          sentEl.textContent = st.e + ' ' + s;
        }
        const sumEl = document.getElementById('autoBriefSummary');
        if (sumEl) sumEl.textContent = latest.summary || latest.analysis?.summary || '';
        const themesEl = document.getElementById('autoBriefThemes');
        if (themesEl) {
          const themes = latest.analysis?.key_themes || [];
          themesEl.innerHTML = themes.slice(0, 5).map(t =>
            `<span style="font-size:10px;background:rgba(79,142,255,0.12);border:1px solid rgba(79,142,255,0.25);border-radius:12px;padding:2px 8px;color:#7ba8ff;">${t.emoji || '📌'} ${t.theme}</span>`
          ).join('');
        }
      } catch (e) { console.warn('autoBriefing load err', e); }
    }

    function expandAutoBriefing() {
      try {
        const clips = (window._idbCache && window._idbCache['news_auto_clips'] || []);
        if (!clips.length) { showToast('저장된 브리핑이 없습니다', 'warn'); return; }
        const latest = clips[0];
        const modal = document.getElementById('autoBriefModal');
        const content = document.getElementById('autoBriefModalContent');
        if (!modal || !content) return;
        content.innerHTML = latest.html ||
          `<div style="padding:20px;"><h3 style="color:var(--ac);">📋 ${latest.date} 브리핑</h3><p style="color:var(--tx);white-space:pre-wrap;">${latest.summary || ''}</p></div>`;
        modal.style.display = 'flex';
      } catch (e) { showToast('브리핑 로드 오류', 'err'); }
    }

