          if (statusEl) statusEl.innerHTML = '<span style="color:#4ade80;">✅ ' + processed.length + '개 (전체 ' + allRaw.length + '개 중 필터)</span>';
          plotPanelDots(processed, lat, lng, radius);
          renderPanelMini(processed, lat, lng, radius);
