    // ── 1. acSwitchTab: 옥션원/온비드 서브탭 전환 ─────────────────
    window.acSwitchTab = function (tab) {
      var panes = { a1: 'acPaneA1', onbid: 'acPaneOnbid' };
      var tabs = { a1: 'acTabA1', onbid: 'acTabOnbid' };
      Object.keys(panes).forEach(function (k) {
        var pane = document.getElementById(panes[k]);
        var btn = document.getElementById(tabs[k]);
        if (pane) pane.style.display = (k === tab) ? '' : 'none';
        if (btn) btn.style.opacity = (k === tab) ? '1' : '0.5';
      });
    };

    // ── 2. collectOnbid / collectOnbidUnified: fetchOnbidItems 래퍼 ──
    // 구버전 버튼(L2882)과 통합버튼(L2457) 모두 fetchOnbidItems로 연결
    window.collectOnbid = function () {
      if (typeof fetchOnbidItems === 'function') fetchOnbidItems('collect');
      else if (typeof showToast === 'function') showToast('온비드 수집 기능을 찾을 수 없습니다', 'warn');
    };
    window.collectOnbidUnified = function () {
      if (typeof fetchOnbidItems === 'function') fetchOnbidItems('panel2');
      else if (typeof showToast === 'function') showToast('온비드 수집 기능을 찾을 수 없습니다', 'warn');
    };

    // ── 3. sbizToggleLayer: 상권분석 레이어 on/off (renderAccordion 버튼용) ──
    window.sbizToggleLayer = function (catId) {
      var mksRef = window.sbizShopMks || {};
      var mapInst = window.sbizMapInst || window.map;
      var list = mksRef[catId] || [];
      // 현재 상태 감지 (첫 마커의 지도 여부로 판단)
      var firstMk = list[0] && (list[0].mk || list[0]);
      var isVisible = false;
      try { isVisible = !!(firstMk && firstMk.getMap()); } catch (e) { }
      var targetMap = isVisible ? null : mapInst;
      list.forEach(function (o) {
        var m = o.mk || o;
        try { m.setMap(targetMap); } catch (e) { }
      });
    };

    // ── 4. sbizMapInst: window.map 의 alias (plotOnMap 함수용) ──────
    // plotOnMap은 sbizMapInst를 사용하므로 window.map 참조로 초기화
    if (typeof sbizMapInst === 'undefined') {
      Object.defineProperty(window, 'sbizMapInst', {
        get: function () { return window.map || null; },
        configurable: true
      });
    }

    // ── 5. clearAllMarkers: clearMapMarkers 의 alias (plotOnMap 내부용) ──
    window.clearAllMarkers = function () {
      if (typeof clearMapMarkers === 'function') clearMapMarkers();
    };

    // ── 6. insNotes / saveNotes / openNote / currentNoteId ───────────
    // 구버전 노트 시스템 → 신버전(nt prefix) 함수로 연결
    // insNotes: ntNotes(nt_notes) 데이터를 읽어 ins_notes 와 병합
    if (typeof insNotes === 'undefined') {
      Object.defineProperty(window, 'insNotes', {
        get: function () {
          // nt 시스템 우선, 없으면 ins_notes fallback
          if (typeof ntNotes !== 'undefined') return ntNotes;
          try { return (window._idbCache && window._idbCache['nt_notes'] || []); } catch (e) { return []; }
        },
        configurable: true
      });
    }
    window.saveNotes = function () {
      if (typeof ntSave === 'function') ntSave();
    };
    window.openNote = function (id) {
      if (typeof ntOpen === 'function') ntOpen(id);
    };
    if (typeof currentNoteId === 'undefined') {
      Object.defineProperty(window, 'currentNoteId', {
        get: function () { return (typeof ntActiveId !== 'undefined') ? ntActiveId : null; },
        configurable: true
      });
    }



    // ════════════════════════════════════════════════════════════
    // 🗂 작업룸 대시보드 v235
    // IIFE 없이 전역으로 선언 — onclick에서 직접 호출 가능
    // ════════════════════════════════════════════════════════════

    var _wrDb = {
      activeId: null,
      filter: 'all',
      view: 'dash'
    };

    // 통합 상태 체계: 파이프라인(watchStatus) = 작업룸(status) 동일 key
    var UNIFIED_STATUS = {
      interest: { label: '📋 개요',  color: '#94a3b8', bg: 'rgba(148,163,184,.15)' },
      review:   { label: '🔍 검토중', color: '#60a5fa', bg: 'rgba(96,165,250,.15)'  },
      field:    { label: '📍 현장',   color: '#fbbf24', bg: 'rgba(251,191,36,.15)'  },
      bid:      { label: '🎯 입찰',   color: '#f97316', bg: 'rgba(249,115,22,.15)'  },
      won:      { label: '✅ 낙찰',   color: '#4ade80', bg: 'rgba(74,222,128,.15)'  },
      sell:     { label: '💰 매도',   color: '#f472b6', bg: 'rgba(244,114,182,.15)' },
      pass:     { label: '🚫 패스',   color: '#6b7280', bg: 'rgba(107,114,128,.15)' }
    };
    // 기존 한글 status 마이그레이션 맵
    var _STATUS_MIGRATE = {
      '개요':'interest',
      '검토중':'review','현장예정':'field','입찰준비':'bid','완료':'won','패스':'pass',
      '검토중 ':'review','현장예정 ':'field'  // 공백 방어
    };
    function _migrateStatus(s) { return _STATUS_MIGRATE[s] || s || 'interest'; }
    var WR_STATUS_COLORS = {  // 하위호환 유지
      review:  UNIFIED_STATUS.review,
      field:   UNIFIED_STATUS.field,
      bid:     UNIFIED_STATUS.bid,
      won:     UNIFIED_STATUS.won,
      pass:    UNIFIED_STATUS.pass,
      interest:UNIFIED_STATUS.interest,
      sell:    UNIFIED_STATUS.sell,
      // 한글 키도 유지 (기존 데이터 방어)
      '검토중': UNIFIED_STATUS.review,
      '현장예정': UNIFIED_STATUS.field,
      '입찰준비': UNIFIED_STATUS.bid,
      '완료': UNIFIED_STATUS.won,
      '패스': UNIFIED_STATUS.pass
    };

    var WR_ANALYSIS_ITEMS = [
      '권리분석', '임차인 현황', '등기부 확인', '현장 임장',
      '배후세대 조사', '인근 임대료 비교', '상권 분석', '수익률 계산'
    ];

    function _wrDbGetSt(val) {
      var key = _migrateStatus(val);
      return WR_STATUS_COLORS[key] || WR_STATUS_COLORS['review'];
    }
    function _wrDbEsc(s) { return String(s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;'); }
    function _wrDbFmt억(v) {
      if (!v) return '-';
      var n = Number(v);
      if (n >= 100000000) return (n / 100000000).toFixed(1) + '억';
      if (n >= 10000) return Math.round(n / 10000) + '만';
      return n.toLocaleString() + '원';
    }

    // ── 필터 토글 ─────────────────────────────────────────────
    function wrDbToggleFilter(btn, val) {
      _wrDb.filter = val;
      document.querySelectorAll('.wr-db-filter-btn').forEach(function (b) { b.classList.remove('on'); });
      btn.classList.add('on');
      wrDbRenderList();
    }

    // ── 뷰 전환 ───────────────────────────────────────────────
    function wrDbSwitchView(mode) {
      _wrDb.view = mode;
      var dashBtn = document.getElementById('wrViewDashBtn');
      var listBtn = document.getElementById('wrViewListBtn');
      if (dashBtn) dashBtn.classList.toggle('on', mode === 'dash');
      if (listBtn) listBtn.classList.toggle('on', mode === 'list');
      if (_wrDb.activeId) wrDbOpenRoom(_wrDb.activeId);
    }

    // ── 리스트 렌더 ───────────────────────────────────────────
    function wrDbRenderList() {
      var list = document.getElementById('wrDbRoomList');
      if (!list) return;

      var rooms = (typeof wrGetRooms === 'function') ? wrGetRooms() : [];
      var query = ((document.getElementById('wrDbSearch') || {}).value || '').trim().toLowerCase();

      var countEl = document.getElementById('wrDbRoomCount');
      if (countEl) countEl.textContent = rooms.length ? '(' + rooms.length + '개)' : '';

      var filtered = rooms.filter(function (r) {
        if (_wrDb.filter !== 'all' && r.status !== _wrDb.filter) return false;
        if (query) {
          return (r.name || '').toLowerCase().indexOf(query) >= 0 ||
            (r.memo || '').toLowerCase().indexOf(query) >= 0;
        }
        return true;
      });

      if (!filtered.length) {
        list.innerHTML = '<div style="display:flex;flex-direction:column;align-items:center;justify-content:center;height:150px;color:var(--mu);gap:8px;font-size:11px;text-align:center;">'
          + (rooms.length ? '<div>조건에 맞는 작업룸이 없습니다</div>'
            : '<div>작업룸이 없습니다<br><span style="font-size:10px;color:var(--di);">상단 "＋ 새 작업룸"으로 추가</span></div>')
          + '</div>';
        return;
      }

      var ORDER = ['bid','field','review','interest','won','pass'];
      filtered.sort(function (a, b) {
        var sa = _migrateStatus(a.status || 'review'), sb = _migrateStatus(b.status || 'review');
        var ia = ORDER.indexOf(sa), ib = ORDER.indexOf(sb);
        return (ia < 0 ? 99:ia) - (ib < 0 ? 99:ib);
      });

      list.innerHTML = filtered.map(function (r) {
        var st = _wrDbGetSt(r.status);
        var d = new Date(r.updatedAt || Date.now());
        var dt = (d.getMonth() + 1) + '/' + d.getDate();
        var markerCnt = r.mapScene ? (r.mapScene.cards || []).filter(function (c) { return c.lat && c.lng; }).length : 0;
        var isActive = _wrDb.activeId === r.id;

        var priceStr = '';
        try {
          if (typeof getSv === 'function' && (r.linkedItems || []).length) {
            var sv = getSv();
            var linked = sv.find(function (it) { return r.linkedItems.indexOf(it.id) >= 0; });
            if (linked) { var p = linked.data && (linked.data['최저가'] || linked.data['감정가']); if (p) priceStr = _wrDbFmt억(p); }
          }
        } catch (e) { }

        var prog = _wrCalcProgress(r);
        var progColor = prog >= 100 ? '#4ade80' : prog >= 50 ? '#4f8eff' : 'rgba(255,255,255,.2)';
        return '<div class="wr-item-card' + (isActive ? ' active' : '') + '" onclick="wrDbOpenRoom(\'' + r.id + '\')">'
          + '<div class="wr-item-addr" title="' + _wrDbEsc(r.name) + '">' + _wrDbEsc(r.name) + '</div>'
          + '<div class="wr-item-row">'
          + '<span class="wr-status-badge" style="color:' + st.color + ';background:' + st.bg + ';border-color:' + st.color + '44;">' + ((UNIFIED_STATUS[_migrateStatus(r.status)] || {}).label || r.status) + '</span>'
          + (priceStr ? '<span class="wr-item-price">' + priceStr + '</span>' : '')
          + '<span style="font-size:9px;color:var(--di);margin-left:auto;">' + dt + '</span>'
          + '</div>'
          + (prog > 0 ? '<div style="display:flex;align-items:center;gap:5px;margin-top:4px;">'
            + '<div style="flex:1;height:2px;background:rgba(255,255,255,.08);border-radius:1px;overflow:hidden;">'
            + '<div style="height:100%;width:' + prog + '%;background:' + progColor + ';transition:width .3s;"></div>'
            + '</div>'
            + '<span style="font-size:9px;color:var(--di);">' + prog + '%</span>'
            + '</div>' : '')
          + (markerCnt > 0 ? '<div style="font-size:9px;color:#4ade80;margin-top:2px;">📍 ' + markerCnt + '개</div>' : '')
          + '</div>';
      }).join('');
    }

    // ── 룸 열기 ───────────────────────────────────────────────
    function wrDbOpenRoom(id) {
      _wrDb.activeId = id;
      wrDbRenderList();

      var room = (typeof wrGetRoom === 'function') ? wrGetRoom(id) : null;
      var detail = document.getElementById('wrDbDetail');
      if (!detail) return;
      if (!room) {
        detail.innerHTML = '<div class="wr-db-empty"><div>룸을 찾을 수 없습니다</div></div>';
        return;
      }

      if (_wrDb.view === 'list') {
        detail.style.overflowY = 'auto';
        detail.style.padding = '14px 16px';
        detail.innerHTML = _wrDbBuildDetailHtml(id, room);
        return;
      }

      detail.style.overflowY = 'hidden';
      detail.style.padding = '0';
      detail.innerHTML = _wrDbBuildDashHtml(id, room);
      setTimeout(function () { _wrDbRenderMiniMap(id, room); }, 50);
    }

    // ════════════════════════════════════════════════════════════
