    // ── 기본 단계 템플릿 ──────────────────────────────────────
    var WR_PHASE_TEMPLATES = [
      {
        id: 'ph_review', label: '검토', icon: '🔍', sections: [
          { id: 'rv_m1', type: 'metrics', title: '핵심 수치', locked: true },
          {
            id: 'rv_c1', type: 'checklist', title: '검토 체크리스트', items: [
              { t: '권리분석 확인', d: false }, { t: '등기부등본 검토', d: false }, { t: '임차인 현황 파악', d: false },
              { t: '감정가 / 최저가 적정성', d: false }, { t: '경매 히스토리 조회', d: false }, { t: '배후세대 / 상권 조사', d: false }
            ]
          },
          { id: 'rv_n1', type: 'memo', title: '권리 분석 메모', content: '' },
          { id: 'rv_n2', type: 'memo', title: '초기 투자 판단', content: '' }
        ]
      },
      {
        id: 'ph_field', label: '임장', icon: '📍', sections: [
          {
            id: 'fd_c1', type: 'checklist', title: '임장 체크리스트', items: [
              { t: '외관·입지 확인', d: false }, { t: '건물 상태 (노후도, 하자)', d: false },
              { t: '임차인 면담 시도', d: false }, { t: '인근 임대료 시세 조사', d: false },
              { t: '교통·편의시설 확인', d: false }, { t: '사진 촬영', d: false }, { t: '인근 중개사 방문', d: false }
            ]
          },
          { id: 'fd_n1', type: 'memo', title: '현장 메모', content: '' },
          { id: 'fd_n2', type: 'memo', title: '임차인 현황', content: '' },
          { id: 'fd_d1', type: 'date_log', title: '임장 일정', logs: [] }
        ]
      },
      {
        id: 'ph_bid', label: '입찰', icon: '🎯', sections: [
          { id: 'bd_m1', type: 'metrics', title: '입찰가 계산', locked: false },
          {
            id: 'bd_c1', type: 'checklist', title: '입찰 준비 체크', items: [
              { t: '입찰가 확정', d: false }, { t: '입찰 보증금 준비 (10~20%)', d: false },
              { t: '신분증·도장 준비', d: false }, { t: '입찰표 작성 연습', d: false },
              { t: '법원 위치·시간 확인', d: false }, { t: '대리 입찰 시 위임장 준비', d: false }
            ]
          },
          { id: 'bd_n1', type: 'memo', title: '입찰 전략 메모', content: '' },
          { id: 'bd_d1', type: 'date_log', title: '입찰 기록', logs: [] }
        ]
      },
      {
        id: 'ph_won', label: '낙찰후', icon: '🏆', sections: [
          {
            id: 'wn_c1', type: 'checklist', title: '낙찰 후 체크', items: [
              { t: '잔금 기한 확인', d: false }, { t: '대출 심사 진행', d: false },
              { t: '명도 계획 수립', d: false }, { t: '등기 이전 신청', d: false },
              { t: '취득세 납부', d: false }, { t: '수리/리모델링 견적', d: false }, { t: '임대 광고 게시', d: false }
            ]
          },
          { id: 'wn_n1', type: 'memo', title: '명도 메모', content: '' },
          { id: 'wn_n2', type: 'memo', title: '수리 계획', content: '' },
          { id: 'wn_m1', type: 'metrics', title: '실제 비용 정산', locked: false }
        ]
      },
      {
        id: 'ph_sell', label: '매도', icon: '💰', sections: [
          { id: 'sl_m1', type: 'metrics', title: '매도 수익 계산', locked: false },
          {
            id: 'sl_c1', type: 'checklist', title: '매도 체크', items: [
              { t: '매도가 목표 설정', d: false }, { t: '중개사 선정', d: false },
              { t: '매도 광고 등록', d: false }, { t: '양도세 시뮬레이션', d: false },
              { t: '계약서 작성', d: false }, { t: '잔금 및 소유권 이전', d: false }
            ]
          },
          { id: 'sl_n1', type: 'memo', title: '매도 전략', content: '' },
          { id: 'sl_d1', type: 'date_log', title: '매도 일정', logs: [] }
        ]
      }
    ];

    // ── 누락 함수: 작업룸 이름 변경 ──────────────────────────
    window.wrDbUpdateName = function (id, val) {
      var rooms = wrGetRooms();
      var room = rooms.find(function (r) { return r.id === id; });
      if (!room) return;
      room.name = val.trim() || room.name;
      room.updatedAt = Date.now();
      wrSetRooms(rooms);
      wrDbRenderList();
    };

    // ── 누락 함수: 작업룸 상태 변경 ─────────────────────────
    window.wrDbUpdateStatus = function (id, val) {
      var rooms = wrGetRooms();
      var room = rooms.find(function (r) { return r.id === id; });
      if (!room) return;
      var newStatus = _migrateStatus(val);
      room.status = newStatus;
      room.phase = newStatus;
      room.updatedAt = Date.now();
      wrSetRooms(rooms);
      wrDbRenderList();
      // ★ 파이프라인 칸반도 갱신
      if (typeof renderWatchBoard === 'function') setTimeout(renderWatchBoard, 50);
    };

    // ── 누락 함수: 물건 연결 (경매+일반 모두) ─────────────────
    window.wrDbLinkItem = function (id, itemId) {
      if (!itemId) return;
      var rooms = wrGetRooms();
      var room = rooms.find(function (r) { return r.id === id; });
      if (!room) return;
      if (!room.linkedItems) room.linkedItems = [];
      if (room.linkedItems.indexOf(itemId) < 0) {
        room.linkedItems.push(itemId);
        room.updatedAt = Date.now();
        wrSetRooms(rooms);
        wrDbOpenRoom(id); // 화면 새로고침
        showToast('✅ 물건이 연결됐습니다', 'ok');
      }
    };

    // ── 유틸 ──────────────────────────────────────────────────
    // _wrPhaseGet: 새 룸 phases 초기화 후 즉시 저장까지 처리
    function _wrPhaseGet(room) {
      if (!room.phases || !room.phases.length) {
        room.phases = JSON.parse(JSON.stringify(WR_PHASE_TEMPLATES));
        room.activePhase = room.phases[0].id;
        // ✅ 수정: 메모리에만 있던 것을 localStorage에도 즉시 저장
        var rooms = wrGetRooms();
        var idx = rooms.findIndex(function (r) { return r.id === room.id; });
        if (idx >= 0) { rooms[idx] = room; wrSetRooms(rooms); }
      }
      return room.phases;
    }
    function _wrPhaseEsc(s) { return String(s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;'); }
    function _wrPhaseFmtAmt(v) {
      if (!v) return '-';
      var n = parseInt(String(v).replace(/[^0-9]/g, '')) || 0;
      if (n >= 100000000) return (n / 100000000).toFixed(1) + '억';
      if (n >= 10000) return Math.round(n / 10000) + '만';
      return n.toLocaleString();
    }

    // ── 파이프라인 단계 → 작업룸 단계 자동 매핑 ─────────────
    var _wrPipelinePhaseMap = {
      interest: 'interest',
      review:   'review',
      field:    'field',
      bid:      'bid',
      won:      'won'
    };

    // ── 작업룸 목록 진행률 계산 ───────────────────────────────
    function _wrCalcProgress(room) {
      var phases = room.phases || WR_PHASE_TEMPLATES;
      var total = 0, done = 0;
      phases.forEach(function (ph) {
        (ph.sections || []).forEach(function (sec) {
          if (sec.type === 'checklist') {
            (sec.items || []).forEach(function (it) { total++; if (it.d) done++; });
          }
        });
      });
      return total ? Math.round(done / total * 100) : 0;
    }

    // ── 메인 대시보드 ────────────────────────────────────────
    function _wrDbBuildDashHtml(id, room) {
      var phases = _wrPhaseGet(room);
      var activeId = room.activePhase || phases[0].id;
      var activePhase = phases.find(function (p) { return p.id === activeId; }) || phases[0];

      var sv = (typeof getSv === 'function') ? getSv() : [];
      var linkedItems = (room.linkedItems || []).map(function (lid) { return sv.find(function (it) { return it.id === lid; }); }).filter(Boolean);
      var mainItem = linkedItems[0];
      var d = (mainItem && mainItem.data) || {};
      var ia = mainItem && mainItem.mode === 'auction';
      var 감정가 = d['감정가'] ? parseInt(String(d['감정가']).replace(/[^0-9]/g, '')) || 0 : 0;
      var 최저가 = d['최저가'] ? parseInt(String(d['최저가']).replace(/[^0-9]/g, '')) || 0 : 0;
      var 매매가 = d['매매가'] ? parseInt(String(d['매매가']).replace(/[^0-9]/g, '')) || 0 : 0;
      var mainPrice = ia ? 최저가 : 매매가;
      var 소재지 = d['소재지'] || (mainItem && mainItem.title) || '';
      var 매각일 = d['매각기일'] || d['매각일'] || '';
      var 면적 = d['전용면적'] || d['건물면적'] || '';

      // D-day
      var ddayBadge = '';
      if (매각일) {
        var dDay = Math.ceil((new Date(매각일) - new Date()) / (1000 * 60 * 60 * 24));
        var dc = dDay < 0 ? '#6b7280' : dDay <= 3 ? '#ff6370' : dDay <= 7 ? '#f97316' : '#4ade80';
        ddayBadge = '<span style="padding:2px 8px;border-radius:5px;background:' + dc + '22;color:' + dc + ';border:1px solid ' + dc + '44;font-size:11px;font-weight:700;flex-shrink:0;">' + (dDay < 0 ? '종료' : (dDay === 0 ? 'D-Day' : 'D-' + dDay)) + '</span>';
      }

      var ws = mainItem ? (mainItem.watchStatus || '') : '';
      var wsLabel = { interest: '📋 개요', review: '🔍 검토중', bid: '🎯 입찰예정', '': '—' }[ws] || '—';
      var wsColor = { interest: '#94a3b8', review: '#60a5fa', field: '#fbbf24', bid: '#f97316', won: '#4ade80', pass: '#6b7280', '': '#4b5563' }[ws] || '#4b5563';
      var st = _wrDbGetSt(room.status);

      // 아이템 셀렉트 (경매 + 일반매물 모두 포함)
      var itemOpts = sv.map(function (it) {
        var addr = (it.data && it.data['소재지'] || it.title || it.id).substring(0, 22);
        var tag = it.mode === 'auction' ? '⚖️' : '🏠';
        return '<option value="' + it.id + '">' + tag + ' ' + _wrPhaseEsc(addr) + '</option>';
      }).join('');

      // 단계 탭
      var phaseTabsHtml = phases.map(function (ph) {
        var isActive = ph.id === activeId;
        // 각 단계의 체크리스트 진행률
        var phDone = 0, phTotal = 0;
        (ph.sections || []).forEach(function (s) {
          if (s.type === 'checklist') (s.items || []).forEach(function (it) { phTotal++; if (it.d) phDone++; });
        });
        var progStr = phTotal ? ' <span style="font-size:9px;opacity:.7;">(' + phDone + '/' + phTotal + ')</span>' : '';
        return '<button onclick="_wrPhaseSwitch(\'' + id + '\',\'' + ph.id + '\')" '
          + 'style="display:flex;align-items:center;gap:4px;padding:5px 11px;border-radius:7px;'
          + 'border:1px solid ' + (isActive ? 'rgba(17,157,237,.55)' : 'var(--b1)') + ';'
          + 'background:' + (isActive ? 'rgba(17,157,237,.15)' : 'transparent') + ';'
          + 'color:' + (isActive ? '#119ded' : 'var(--mu)') + ';'
          + 'font-size:11px;font-weight:' + (isActive ? '700' : '400') + ';cursor:pointer;white-space:nowrap;'
          + 'font-family:\'Noto Sans KR\',sans-serif;transition:all .15s;" '
          + 'onmouseenter="if(this.style.color!==\'rgb(167, 139, 250)\')this.style.color=\'var(--tx)\';" '
          + 'onmouseleave="if(this.style.color!==\'rgb(167, 139, 250)\')this.style.color=\'var(--mu)\';">'
          + '<span>' + ph.icon + '</span><span>' + _wrPhaseEsc(ph.label) + progStr + '</span>'
          + '</button>';
      }).join('');

      // 섹션들
      var sectionsHtml = (activePhase.sections || []).map(function (sec, si) {
        return _wrPhaseRenderSection(id, room, activePhase, sec, si, mainItem, d, ia, 감정가, 최저가, mainPrice);
      }).join('');

      return '<div style="display:flex;flex-direction:column;height:100%;overflow:hidden;font-family:\'Noto Sans KR\',sans-serif;">'

        // ── 헤더 ──
        + '<div style="display:flex;align-items:center;gap:6px;padding:7px 12px;border-bottom:1px solid var(--b1);flex-shrink:0;background:var(--s1);flex-wrap:wrap;">'
        + '<input value="' + _wrPhaseEsc(room.name) + '" onchange="wrDbUpdateName(\'' + id + '\',this.value)" '
        + 'style="min-width:60px;max-width:200px;background:transparent;border:none;border-bottom:1px solid transparent;'
        + 'color:var(--tx);font-size:13px;font-weight:700;outline:none;padding:2px 0;font-family:\'Noto Sans KR\',sans-serif;" '
        + 'onfocus="this.style.borderBottomColor=\'rgba(79,142,255,.4)\'" onblur="this.style.borderBottomColor=\'transparent\'">'
        + '<select onchange="wrDbUpdateStatus(\'' + id + '\',this.value)" '
        + 'style="padding:2px 6px;background:' + st.bg + ';border:1px solid ' + st.color + '55;border-radius:5px;'
        + 'color:' + st.color + ';font-size:10px;font-weight:700;outline:none;cursor:pointer;flex-shrink:0;">'
        + Object.entries(UNIFIED_STATUS).map(function(e) {
            var key = e[0], info = e[1];
            var cur = _migrateStatus(room.status || 'interest');
            return '<option value="' + key + '"' + (key === cur ? ' selected' : '') + '>' + info.label + '</option>';
          }).join('')
        + '</select>'
        + ddayBadge
        + (mainItem ? '<span title="파이프라인 단계 (클릭해서 변경)" style="font-size:9px;padding:2px 6px;border-radius:4px;background:' + wsColor + '18;color:' + wsColor + ';border:1px solid ' + wsColor + '33;cursor:pointer;flex-shrink:0;" onclick="_wbCycleStatusForRoom(\'' + id + '\',\'' + mainItem.id + '\')">' + wsLabel + '</span>' : '')
        + '<div style="flex:1;"></div>'
        + (room.mapScene ? '<button onclick="wrOpenMapScene(\'' + id + '\')" title="지도 열기" style="padding:2px 8px;background:rgba(74,222,128,.1);border:1px solid rgba(74,222,128,.3);border-radius:5px;color:#4ade80;font-size:11px;cursor:pointer;flex-shrink:0;">🗺</button>' : '')
        + '<button onclick="wrCreateNoteFromRoom(\'' + id + '\')" title="분석 노트 만들기" style="padding:2px 7px;background:rgba(17,157,237,.1);border:1px solid rgba(17,157,237,.3);border-radius:5px;color:#119ded;font-size:11px;cursor:pointer;flex-shrink:0;">📓</button>'
        + '<button onclick="wrDeleteRoom(\'' + id + '\')" title="작업룸 삭제" style="padding:2px 6px;background:rgba(255,77,77,.08);border:1px solid rgba(255,77,77,.2);border-radius:5px;color:#ff6370;font-size:11px;cursor:pointer;flex-shrink:0;">🗑</button>'
        + '</div>'

        // ── 물건 요약 바 ──
        + (mainItem ?
          '<div style="display:flex;align-items:center;gap:8px;padding:5px 12px;border-bottom:1px solid var(--b1);flex-shrink:0;background:rgba(0,0,0,.12);flex-wrap:wrap;">'
          + '<span style="font-size:11px;font-weight:600;color:var(--tx);">⚖️ ' + _wrPhaseEsc(소재지.substring(0, 28)) + '</span>'
          + (감정가 ? '<span style="font-size:10px;color:var(--mu);">감정 <b style="color:var(--or);">' + _wrPhaseFmtAmt(감정가) + '</b></span>' : '')
          + (최저가 ? '<span style="font-size:10px;color:var(--mu);">최저 <b style="color:#4ade80;">' + _wrPhaseFmtAmt(최저가) + '</b></span>' : '')
          + (감정가 && 최저가 ? '<span style="font-size:10px;color:var(--mu);">낙찰률 <b style="color:' + (Math.round(최저가 / 감정가 * 100) <= 70 ? '#4ade80' : '#f97316') + ';">' + Math.round(최저가 / 감정가 * 100) + '%</b></span>' : '')
          + (면적 ? '<span style="font-size:10px;color:var(--di);">' + _wrPhaseEsc(String(면적)) + '</span>' : '')
          + '<div style="flex:1;"></div>'
          + (itemOpts ? '<select onchange="wrDbLinkItem(\'' + id + '\',this.value);this.value=\'\';" style="padding:2px 6px;background:var(--s2);border:1px solid var(--b1);border-radius:4px;color:var(--mu);font-size:10px;cursor:pointer;max-width:140px;"><option value="">＋ 물건 추가</option>' + itemOpts + '</select>' : '')
          + '</div>'
          : '<div style="padding:6px 12px;border-bottom:1px solid var(--b1);flex-shrink:0;background:rgba(0,0,0,.12);">'
          + (itemOpts ? '<select onchange="wrDbLinkItem(\'' + id + '\',this.value);this.value=\'\';" style="padding:3px 8px;background:var(--s2);border:1px solid var(--b1);border-radius:5px;color:var(--tx);font-size:11px;cursor:pointer;"><option value="">＋ 저장목록에서 물건 연결</option>' + itemOpts + '</select>' : '<span style="font-size:11px;color:var(--di);">연결된 물건 없음 — 파이프라인에서 🗂 버튼으로 연결하세요</span>')
          + '</div>')

        // ── 단계 탭 바 ──
        + '<div style="display:flex;align-items:center;gap:5px;padding:6px 12px;border-bottom:1px solid var(--b1);flex-shrink:0;overflow-x:auto;background:var(--s2);" id="wrPhaseTabs_' + id + '">'
        + phaseTabsHtml
        + '<div style="flex:1;min-width:6px;"></div>'
        + '<button onclick="_wrPhaseAdd(\'' + id + '\')" title="단계 추가" '
        + 'style="padding:4px 9px;background:transparent;border:1px dashed var(--b1);border-radius:6px;color:var(--di);font-size:10px;cursor:pointer;white-space:nowrap;flex-shrink:0;transition:all .15s;font-family:\'Noto Sans KR\',sans-serif;" '
        + 'onmouseenter="this.style.borderColor=\'rgba(17,157,237,.4)\';this.style.color=\'#119ded\';" '
        + 'onmouseleave="this.style.borderColor=\'var(--b1)\';this.style.color=\'var(--di)\';">＋ 단계</button>'
        + (phases.length > 1 ? '<button onclick="_wrPhaseDelete(\'' + id + '\',\'' + activeId + '\')" title="현재 단계 삭제" '
          + 'style="padding:4px 7px;background:transparent;border:1px solid var(--b1);border-radius:6px;color:var(--di);font-size:10px;cursor:pointer;flex-shrink:0;" '
          + 'onmouseenter="this.style.borderColor=\'rgba(255,99,112,.4)\';this.style.color=\'#ff6370\';" '
          + 'onmouseleave="this.style.borderColor=\'var(--b1)\';this.style.color=\'var(--di)\';">✕ 단계삭제</button>' : '')
        + '</div>'

        // ── 섹션 스크롤 영역 ──
        + '<div style="flex:1;overflow-y:auto;padding:10px 12px;display:flex;flex-direction:column;gap:8px;" id="wrPhaseBody_' + id + '">'
        + sectionsHtml
        + '<button onclick="_wrSecAdd(\'' + id + '\',\'' + activeId + '\')" '
        + 'style="padding:9px;background:transparent;border:1px dashed var(--b1);border-radius:8px;color:var(--di);font-size:11px;cursor:pointer;transition:all .15s;font-family:\'Noto Sans KR\',sans-serif;" '
        + 'onmouseenter="this.style.borderColor=\'rgba(17,157,237,.4)\';this.style.color=\'#119ded\';" '
        + 'onmouseleave="this.style.borderColor=\'var(--b1)\';this.style.color=\'var(--di)\';">＋ 섹션 추가</button>'
        + '</div>'
        + '</div>';
    }

    // ── 섹션 렌더 ────────────────────────────────────────────
    function _wrPhaseRenderSection(roomId, room, phase, sec, si, mainItem, d, ia, 감정가, 최저가, mainPrice) {
      var phId = phase.id;
      var secId = sec.id;
      var collapsed = (room._collapsed || {})[phId + '_' + secId] || false;

      var typeIcon = { 'memo': '📝', 'checklist': '✅', 'metrics': '📊', 'date_log': '📅' }[sec.type] || '•';

      // 섹션 헤더
      var hdr = '<div style="display:flex;align-items:center;gap:5px;padding:7px 10px;'
        + 'background:rgba(0,0,0,.1);cursor:pointer;" onclick="_wrSecToggleCollapse(\'' + roomId + '\',\'' + phId + '\',\'' + secId + '\')">'
        + '<span style="font-size:10px;color:var(--di);transition:transform .2s;display:inline-block;' + (collapsed ? '' : 'transform:rotate(0deg);') + '" id="collapseArrow_' + roomId + '_' + phId + '_' + secId + '">' + (collapsed ? '▶' : '▼') + '</span>'
        + '<span style="font-size:10px;color:var(--di);flex-shrink:0;">' + typeIcon + '</span>'
        + '<span style="font-size:11px;font-weight:700;color:var(--tx);flex:1;">' + _wrPhaseEsc(sec.title) + '</span>'
        // 버튼들은 클릭전파 중단
        + '<span onclick="event.stopPropagation();_wrSecRename(\'' + roomId + '\',\'' + phId + '\',\'' + secId + '\')" '
        + 'title="제목 변경" style="padding:2px 5px;color:var(--di);font-size:11px;cursor:pointer;border-radius:3px;opacity:.5;" '
        + 'onmouseenter="this.style.opacity=1;this.style.background=\'rgba(255,255,255,.08)\';" onmouseleave="this.style.opacity=\'.5\';this.style.background=\'transparent\';">✎</span>'
        + (!sec.locked ? '<span onclick="event.stopPropagation();_wrSecDelete(\'' + roomId + '\',\'' + phId + '\',\'' + secId + '\')" '
          + 'title="섹션 삭제" style="padding:2px 5px;color:var(--di);font-size:11px;cursor:pointer;border-radius:3px;opacity:.4;" '
          + 'onmouseenter="this.style.opacity=1;this.style.color=\'#ff6370\';this.style.background=\'rgba(255,99,112,.1)\';" onmouseleave="this.style.opacity=\'.4\';this.style.color=\'var(--di)\';this.style.background=\'transparent\';">✕</span>' : '')
        + '</div>';

      var body = '';

      // ── 메모 ──
      if (sec.type === 'memo') {
        body = '<textarea '
          + 'oninput="_wrSecSaveMemo(\'' + roomId + '\',\'' + phId + '\',\'' + secId + '\',this.value)" '
          + 'style="width:100%;min-height:80px;resize:vertical;background:transparent;border:none;color:var(--tx);'
          + 'font-size:11px;line-height:1.75;outline:none;font-family:\'Noto Sans KR\',sans-serif;box-sizing:border-box;" '
          + 'placeholder="' + _wrPhaseEsc(sec.title) + ' 메모를 입력하세요...">'
          + _wrPhaseEsc(sec.content || '')
          + '</textarea>';
      }

      // ── 체크리스트 ──
      else if (sec.type === 'checklist') {
        var items = sec.items || [];
        var doneN = items.filter(function (it) { return it.d; }).length;
        var pct = items.length ? Math.round(doneN / items.length * 100) : 0;
        body = '<div>'
          + '<div style="display:flex;align-items:center;gap:7px;margin-bottom:8px;">'
          + '<div style="flex:1;height:3px;background:var(--b1);border-radius:2px;overflow:hidden;">'
          + '<div style="height:100%;width:' + pct + '%;background:linear-gradient(90deg,#4f8eff,#00d4aa);transition:width .3s;"></div>'
          + '</div>'
          + '<span style="font-size:9px;color:var(--di);">' + doneN + '/' + items.length + '</span>'
          + '</div>'
          + items.map(function (it, ii) {
            return '<div style="display:flex;align-items:center;gap:7px;padding:4px 2px;border-radius:4px;cursor:pointer;transition:background .1s;group" '
              + 'onclick="_wrSecCheckToggle(\'' + roomId + '\',\'' + phId + '\',\'' + secId + '\',' + ii + ')" '
              + 'onmouseenter="this.style.background=\'rgba(255,255,255,.04)\'" onmouseleave="this.style.background=\'transparent\'">'
              + '<div style="width:15px;height:15px;border-radius:3px;flex-shrink:0;display:flex;align-items:center;justify-content:center;transition:all .15s;'
              + 'border:1.5px solid ' + (it.d ? '#4ade80' : 'rgba(255,255,255,.2)') + ';background:' + (it.d ? '#4ade80' : 'transparent') + ';">'
              + (it.d ? '<span style="font-size:9px;color:#111;font-weight:800;">✓</span>' : '')
              + '</div>'
              + '<span style="font-size:11px;flex:1;color:' + (it.d ? 'var(--di)' : 'var(--tx)') + ';' + (it.d ? 'text-decoration:line-through;' : '') + '">'
              + _wrPhaseEsc(it.t)
              + '</span>'
              + '<span onclick="event.stopPropagation();_wrSecCheckDelete(\'' + roomId + '\',\'' + phId + '\',\'' + secId + '\',' + ii + ')" '
              + 'style="padding:0 4px;color:transparent;font-size:12px;cursor:pointer;flex-shrink:0;" '
              + 'onmouseenter="this.style.color=\'var(--di)\';" onmouseleave="this.style.color=\'transparent\';">✕</span>'
              + '</div>';
          }).join('')
          + '<div style="display:flex;gap:5px;margin-top:8px;">'
          + '<input id="ckIn_' + roomId + '_' + phId + '_' + secId + '" placeholder="항목 추가... (Enter)" '
          + 'style="flex:1;background:var(--s1);border:1px solid var(--b1);border-radius:5px;color:var(--tx);font-size:11px;padding:4px 8px;outline:none;font-family:\'Noto Sans KR\',sans-serif;transition:border-color .15s;" '
          + 'onfocus="this.style.borderColor=\'rgba(79,142,255,.4)\'" onblur="this.style.borderColor=\'var(--b1)\'" '
          + 'onkeydown="if(event.key===\'Enter\')_wrSecCheckAdd(\'' + roomId + '\',\'' + phId + '\',\'' + secId + '\')">'
          + '<button onclick="_wrSecCheckAdd(\'' + roomId + '\',\'' + phId + '\',\'' + secId + '\')" '
          + 'style="padding:4px 10px;background:rgba(79,142,255,.12);border:1px solid rgba(79,142,255,.3);border-radius:5px;color:#4f8eff;font-size:12px;cursor:pointer;transition:all .15s;" '
          + 'onmouseenter="this.style.background=\'rgba(79,142,255,.25)\'" onmouseleave="this.style.background=\'rgba(79,142,255,.12)\'">＋</button>'
          + '</div>'
          + '</div>';
      }

      // ── 수치/계산 ──
      else if (sec.type === 'metrics') {
        var rows = sec.rows || [];
        var autoRows = [];
        // 단계별 자동 데이터
        if (phase.id === 'ph_review' || phase.id === 'ph_bid') {
          if (감정가) autoRows.push({ k: '감정가', v: _wrPhaseFmtAmt(감정가) });
          if (최저가) autoRows.push({ k: '최저가', v: _wrPhaseFmtAmt(최저가) });
          if (감정가 && 최저가) autoRows.push({ k: '낙찰가율', v: Math.round(최저가 / 감정가 * 100) + '%' });
          if (mainItem && mainItem.data && mainItem.data['면적']) autoRows.push({ k: '면적', v: String(mainItem.data['면적']) });
        }
        if (phase.id === 'ph_won' || phase.id === 'ph_sell') {
          if (감정가) autoRows.push({ k: '감정가', v: _wrPhaseFmtAmt(감정가) });
          var buyP = room.actualBuyPrice || 최저가;
          if (buyP) autoRows.push({ k: '낙찰가', v: _wrPhaseFmtAmt(buyP) });
        }
        // 수익률 시뮬 (검토/입찰 단계에서만)
        var yieldHtml = '';
        if (mainPrice && (phase.id === 'ph_review' || phase.id === 'ph_bid')) {
          yieldHtml = '<div style="margin-top:8px;padding-top:8px;border-top:1px solid var(--b1);">'
            + '<div style="font-size:9px;color:var(--mu);margin-bottom:5px;font-weight:700;letter-spacing:.4px;">월세 수익률 시뮬</div>'
            + '<table style="width:100%;border-collapse:collapse;">'
            + [5, 6, 7].map(function (r, i) {
              var m = Math.round(mainPrice * r / 100 / 12 / 10000);
              return '<tr style="' + (i === 1 ? 'background:rgba(0,212,170,.06);' : '') + '"><td style="font-size:10px;color:var(--mu);padding:3px 4px;">' + r + '%</td>'
                + '<td style="text-align:right;font-size:10px;font-weight:700;padding:3px 4px;color:' + (i === 1 ? '#00d4aa' : 'var(--tx)') + ';">' + m + '만/월</td></tr>';
            }).join('')
            + '</table></div>';
        }
        body = '<div>'
          + (autoRows.length ? '<table style="width:100%;border-collapse:collapse;margin-bottom:8px;padding-bottom:8px;border-bottom:1px solid var(--b1);">'
            + autoRows.map(function (row) {
              return '<tr><td style="font-size:10px;color:var(--mu);padding:3px 4px;width:44%;">' + _wrPhaseEsc(row.k) + '</td>'
                + '<td style="font-size:11px;font-weight:700;color:var(--tx);text-align:right;padding:3px 4px;">' + _wrPhaseEsc(row.v) + '</td></tr>';
            }).join('')
            + '</table>' : '')
          + (rows.length ? '<table style="width:100%;border-collapse:collapse;margin-bottom:8px;">'
            + rows.map(function (row, ri) {
              return '<tr><td style="padding:2px 2px;width:46%;">'
                + '<input value="' + _wrPhaseEsc(row.k) + '" onchange="_wrMetricRowUpdate(\'' + roomId + '\',\'' + phId + '\',\'' + secId + '\',' + ri + ',\'k\',this.value)" '
                + 'style="width:100%;background:transparent;border:none;border-bottom:1px solid var(--b1);color:var(--mu);font-size:10px;outline:none;font-family:\'Noto Sans KR\',sans-serif;padding:1px 2px;" placeholder="항목명"></td>'
                + '<td style="padding:2px 2px;">'
                + '<input value="' + _wrPhaseEsc(row.v) + '" onchange="_wrMetricRowUpdate(\'' + roomId + '\',\'' + phId + '\',\'' + secId + '\',' + ri + ',\'v\',this.value)" '
                + 'style="width:100%;background:transparent;border:none;border-bottom:1px solid var(--b1);color:var(--tx);font-size:10px;font-weight:700;text-align:right;outline:none;font-family:\'Noto Sans KR\',sans-serif;padding:1px 2px;" placeholder="값"></td>'
                + '<td style="width:16px;padding:0;text-align:right;">'
                + '<span onclick="_wrMetricRowDelete(\'' + roomId + '\',\'' + phId + '\',\'' + secId + '\',' + ri + ')" '
                + 'style="padding:0 3px;color:transparent;font-size:12px;cursor:pointer;" '
                + 'onmouseenter="this.style.color=\'var(--di)\'" onmouseleave="this.style.color=\'transparent\'">✕</span></td></tr>';
            }).join('')
            + '</table>' : '')
          + '<button onclick="_wrMetricRowAdd(\'' + roomId + '\',\'' + phId + '\',\'' + secId + '\')" '
          + 'style="padding:3px 9px;background:transparent;border:1px dashed var(--b1);border-radius:5px;color:var(--di);font-size:10px;cursor:pointer;font-family:\'Noto Sans KR\',sans-serif;transition:all .15s;" '
          + 'onmouseenter="this.style.borderColor=\'rgba(79,142,255,.4)\';this.style.color=\'#4f8eff\';" '
          + 'onmouseleave="this.style.borderColor=\'var(--b1)\';this.style.color=\'var(--di)\';">＋ 항목 추가</button>'
          + yieldHtml
          + '</div>';
      }

      // ── 날짜 기록 ──
      else if (sec.type === 'date_log') {
        var logs = sec.logs || [];
        body = '<div>'
          + (logs.length ? '<div style="margin-bottom:8px;">'
            + logs.map(function (log, li) {
              return '<div style="display:flex;gap:7px;padding:5px 3px;border-bottom:1px solid rgba(255,255,255,.05);align-items:flex-start;">'
                + '<span style="font-size:10px;color:var(--di);white-space:nowrap;padding-top:1px;flex-shrink:0;min-width:52px;">' + _wrPhaseEsc(log.date || '') + '</span>'
                + '<span style="font-size:11px;color:var(--tx);flex:1;line-height:1.5;">' + _wrPhaseEsc(log.text || '') + '</span>'
                + '<span onclick="_wrLogDelete(\'' + roomId + '\',\'' + phId + '\',\'' + secId + '\',' + li + ')" '
                + 'style="padding:0 4px;color:transparent;font-size:12px;cursor:pointer;flex-shrink:0;" '
                + 'onmouseenter="this.style.color=\'var(--di)\'" onmouseleave="this.style.color=\'transparent\'">✕</span>'
                + '</div>';
            }).join('')
            + '</div>' : '')
          + '<div style="display:flex;gap:5px;align-items:center;flex-wrap:wrap;">'
          + '<input type="date" id="logDate_' + roomId + '_' + phId + '_' + secId + '" value="' + new Date().toISOString().slice(0, 10) + '" '
          + 'style="background:var(--s1);border:1px solid var(--b1);border-radius:5px;color:var(--tx);font-size:11px;padding:3px 6px;outline:none;width:128px;flex-shrink:0;" '
          + 'onfocus="this.style.borderColor=\'rgba(79,142,255,.4)\'" onblur="this.style.borderColor=\'var(--b1)\'">'
          + '<input id="logText_' + roomId + '_' + phId + '_' + secId + '" placeholder="기록..." '
          + 'style="flex:1;min-width:80px;background:var(--s1);border:1px solid var(--b1);border-radius:5px;color:var(--tx);font-size:11px;padding:3px 8px;outline:none;font-family:\'Noto Sans KR\',sans-serif;transition:border-color .15s;" '
          + 'onfocus="this.style.borderColor=\'rgba(79,142,255,.4)\'" onblur="this.style.borderColor=\'var(--b1)\'" '
          + 'onkeydown="if(event.key===\'Enter\')_wrLogAdd(\'' + roomId + '\',\'' + phId + '\',\'' + secId + '\')">'
          + '<button onclick="_wrLogAdd(\'' + roomId + '\',\'' + phId + '\',\'' + secId + '\')" '
          + 'style="padding:3px 10px;background:rgba(79,142,255,.12);border:1px solid rgba(79,142,255,.3);border-radius:5px;color:#4f8eff;font-size:12px;cursor:pointer;flex-shrink:0;transition:all .15s;" '
          + 'onmouseenter="this.style.background=\'rgba(79,142,255,.25)\'" onmouseleave="this.style.background=\'rgba(79,142,255,.12)\'">＋</button>'
          + '</div>'
          + '</div>';
      }

      return '<div style="background:var(--s1);border:1px solid var(--b1);border-radius:9px;overflow:hidden;" id="wrSec_' + roomId + '_' + phId + '_' + secId + '">'
        + hdr
        + (collapsed ? ''
          : '<div style="padding:9px 10px;" id="wrSecBody_' + roomId + '_' + phId + '_' + secId + '">' + body + '</div>')
        + '</div>';
    }

    // ════════════════════════════════════════════════════════════
    // 단계/섹션 조작 함수들
    // ════════════════════════════════════════════════════════════

    // ── 단계 전환 ───────────────────────────────────────────
    window._wrPhaseSwitch = function (roomId, phId) {
      var rooms = wrGetRooms();
      var room = rooms.find(function (r) { return r.id === roomId; });
      if (!room) return;
      room.activePhase = phId;
      wrSetRooms(rooms);
      wrDbOpenRoom(roomId);
    };

    // ── 파이프라인 상태 변경 (작업룸 단계와는 분리) ──────────
    window._wbCycleStatusForRoom = function (roomId, itemId) {
      if (typeof cycleWatchStatus === 'function') {
        cycleWatchStatus(itemId);
        setTimeout(function () {
          if (typeof wrDbOpenRoom === 'function') wrDbOpenRoom(roomId);
          if (typeof renderWatchBoard === 'function') renderWatchBoard();
        }, 100);
      }
    };

    // ── 섹션 접기/펼치기 (DOM 직접 조작 - 깜빡임 없음) ─────────
    window._wrSecToggleCollapse = function (roomId, phId, secId) {
      var rooms = wrGetRooms();
      var room = rooms.find(function (r) { return r.id === roomId; });
      if (!room) return;
      if (!room._collapsed) room._collapsed = {};
      var key = phId + '_' + secId;
      room._collapsed[key] = !room._collapsed[key];
      var collapsed = room._collapsed[key];
      wrSetRooms(rooms);

      // DOM 직접 조작 (전체 재렌더 없이)
      var bodyEl = document.getElementById('wrSecBody_' + roomId + '_' + phId + '_' + secId);
      var arrowEl = document.getElementById('collapseArrow_' + roomId + '_' + phId + '_' + secId);
      if (bodyEl) bodyEl.style.display = collapsed ? 'none' : '';
      if (arrowEl) arrowEl.textContent = collapsed ? '▶' : '▼';
    };

    // ── 단계 추가 ─────────────────────────────────────────────
    window._wrPhaseAdd = function (roomId) {
      var label = prompt('새 단계 이름을 입력하세요:');
      if (!label || !label.trim()) return;
      var rooms = wrGetRooms();
      var room = rooms.find(function (r) { return r.id === roomId; });
      if (!room) return;
      _wrPhaseGet(room);
      var ts = Date.now();
      var newPh = {
        id: 'ph_custom_' + ts, label: label.trim(), icon: '📌',
        sections: [{ id: 'cu_n1_' + ts, type: 'memo', title: '메모', content: '' }]
      };
      room.phases.push(newPh);
      room.activePhase = newPh.id;
      wrSetRooms(rooms);
      wrDbOpenRoom(roomId);
    };

    // ── 단계 삭제 ─────────────────────────────────────────────
    window._wrPhaseDelete = function (roomId, phId) {
      if (!confirm('이 단계를 삭제할까요? 내용이 모두 사라집니다.')) return;
      var rooms = wrGetRooms();
      var room = rooms.find(function (r) { return r.id === roomId; });
      if (!room) return;
      _wrPhaseGet(room);
      room.phases = room.phases.filter(function (p) { return p.id !== phId; });
      room.activePhase = room.phases.length ? room.phases[0].id : undefined;
      wrSetRooms(rooms);
      wrDbOpenRoom(roomId);
    };

    // ── 섹션 추가 (타입 선택 UI) ─────────────────────────────
    window._wrSecAdd = function (roomId, phId) {
      // 모달로 타입 선택
      var existing = document.getElementById('_wrSecAddModal');
      if (existing) existing.remove();
      var modal = document.createElement('div');
      modal.id = '_wrSecAddModal';
      modal.style.cssText = 'position:fixed;top:50%;left:50%;transform:translate(-50%,-50%);background:var(--s1,#1a1f2e);border:1px solid var(--b1,#2a3050);border-radius:12px;padding:18px;z-index:99999;width:280px;box-shadow:0 12px 40px rgba(0,0,0,.7);font-family:\'Noto Sans KR\',sans-serif;';
      var types = [
        { type: 'memo', icon: '📝', label: '메모', desc: '자유 텍스트' },
        { type: 'checklist', icon: '✅', label: '체크리스트', desc: '항목 추가/체크' },
        { type: 'metrics', icon: '📊', label: '수치/계산', desc: '숫자·계산 입력' },
        { type: 'date_log', icon: '📅', label: '날짜 기록', desc: '날짜+내용 로그' },
      ];
      modal.innerHTML = '<div style="font-size:13px;font-weight:700;color:var(--tx,#e8eaf6);margin-bottom:12px;">섹션 타입 선택</div>'
        + types.map(function (t) {
          return '<div onclick="_wrSecAddConfirm(\'' + roomId + '\',\'' + phId + '\',\'' + t.type + '\')" '
            + 'style="display:flex;align-items:center;gap:10px;padding:9px 10px;border-radius:7px;border:1px solid var(--b1,#2a3050);margin-bottom:6px;cursor:pointer;transition:all .15s;background:var(--s2,#212840);" '
            + 'onmouseenter="this.style.borderColor=\'rgba(17,157,237,.5)\';this.style.background=\'rgba(17,157,237,.08)\';" '
            + 'onmouseleave="this.style.borderColor=\'var(--b1,#2a3050)\';this.style.background=\'var(--s2,#212840)\'">'
            + '<span style="font-size:20px;">' + t.icon + '</span>'
            + '<div><div style="font-size:12px;font-weight:600;color:var(--tx,#e8eaf6);">' + t.label + '</div>'
            + '<div style="font-size:10px;color:var(--mu,#8899aa);">' + t.desc + '</div></div>'
            + '</div>';
        }).join('')
        + '<button onclick="document.getElementById(\'_wrSecAddModal\').remove()" '
        + 'style="width:100%;margin-top:4px;padding:6px;background:transparent;border:1px solid var(--b1,#2a3050);border-radius:7px;color:var(--mu,#8899aa);font-size:11px;cursor:pointer;font-family:\'Noto Sans KR\',sans-serif;">취소</button>';
      document.body.appendChild(modal);
      setTimeout(function () {
        var close = function (e) { if (!modal.contains(e.target)) { modal.remove(); document.removeEventListener('click', close); } };
        document.addEventListener('click', close);
      }, 100);
    };

    window._wrSecAddConfirm = function (roomId, phId, type) {
      var modal = document.getElementById('_wrSecAddModal');
      if (modal) modal.remove();
      var defaultTitles = { memo: '메모', checklist: '체크리스트', metrics: '수치', date_log: '날짜 기록' };
      var title = prompt('섹션 제목:', defaultTitles[type] || '새 섹션');
      if (!title || !title.trim()) return;
      var rooms = wrGetRooms();
      var room = rooms.find(function (r) { return r.id === roomId; });
      if (!room) return;
      _wrPhaseGet(room);
      var ph = room.phases.find(function (p) { return p.id === phId; });
      if (!ph) return;
      var newSec = { id: 's_' + Date.now(), type: type, title: title.trim() };
      if (type === 'checklist') newSec.items = [];
      if (type === 'metrics') newSec.rows = [];
      if (type === 'date_log') newSec.logs = [];
      if (type === 'memo') newSec.content = '';
      ph.sections.push(newSec);
      wrSetRooms(rooms);
      wrDbOpenRoom(roomId);
    };

    // ── 섹션 삭제 ─────────────────────────────────────────────
    window._wrSecDelete = function (roomId, phId, secId) {
      if (!confirm('이 섹션을 삭제할까요?')) return;
      var rooms = wrGetRooms();
      var room = rooms.find(function (r) { return r.id === roomId; });
      if (!room) return;
      var ph = room.phases && room.phases.find(function (p) { return p.id === phId; });
      if (!ph) return;
      ph.sections = ph.sections.filter(function (s) { return s.id !== secId; });
      wrSetRooms(rooms);
      wrDbOpenRoom(roomId);
    };

    // ── 섹션 제목 변경 ────────────────────────────────────────
    window._wrSecRename = function (roomId, phId, secId) {
      var rooms = wrGetRooms();
      var room = rooms.find(function (r) { return r.id === roomId; });
      if (!room) return;
      var ph = room.phases && room.phases.find(function (p) { return p.id === phId; });
      if (!ph) return;
      var sec = ph.sections.find(function (s) { return s.id === secId; });
      if (!sec) return;
      var name = prompt('섹션 제목:', sec.title);
      if (!name || !name.trim()) return;
      sec.title = name.trim();
      wrSetRooms(rooms);
      wrDbOpenRoom(roomId);
    };

    // ── 메모 저장 (debounce 600ms) ───────────────────────────
    var _wrMemoTimers = {};
    window._wrSecSaveMemo = function (roomId, phId, secId, val) {
      var key = roomId + phId + secId;
      clearTimeout(_wrMemoTimers[key]);
      _wrMemoTimers[key] = setTimeout(function () {
        var rooms = wrGetRooms();
        var room = rooms.find(function (r) { return r.id === roomId; });
        if (!room) return;
        var ph = room.phases && room.phases.find(function (p) { return p.id === phId; });
        if (!ph) return;
        var sec = ph.sections.find(function (s) { return s.id === secId; });
        if (!sec) return;
        sec.content = val;
        room.updatedAt = Date.now();
        wrSetRooms(rooms);
      }, 600);
    };

    // ── 체크리스트 ────────────────────────────────────────────
    window._wrSecCheckToggle = function (roomId, phId, secId, idx) {
      var rooms = wrGetRooms();
      var room = rooms.find(function (r) { return r.id === roomId; });
      if (!room) return;
      var ph = room.phases && room.phases.find(function (p) { return p.id === phId; });
      if (!ph) return;
      var sec = ph.sections.find(function (s) { return s.id === secId; });
      if (!sec || !sec.items) return;
      sec.items[idx].d = !sec.items[idx].d;
      room.updatedAt = Date.now();
      wrSetRooms(rooms);
      wrDbOpenRoom(roomId);
    };
    window._wrSecCheckAdd = function (roomId, phId, secId) {
      var inp = document.getElementById('ckIn_' + roomId + '_' + phId + '_' + secId);
      var text = inp && inp.value.trim();
      if (!text) return;
      var rooms = wrGetRooms();
      var room = rooms.find(function (r) { return r.id === roomId; });
      if (!room) return;
      var ph = room.phases && room.phases.find(function (p) { return p.id === phId; });
      if (!ph) return;
      var sec = ph.sections.find(function (s) { return s.id === secId; });
      if (!sec) return;
      if (!sec.items) sec.items = [];
      sec.items.push({ t: text, d: false });
      room.updatedAt = Date.now();
      wrSetRooms(rooms);
      wrDbOpenRoom(roomId);
    };
    window._wrSecCheckDelete = function (roomId, phId, secId, idx) {
      var rooms = wrGetRooms();
      var room = rooms.find(function (r) { return r.id === roomId; });
      if (!room) return;
      var ph = room.phases && room.phases.find(function (p) { return p.id === phId; });
      if (!ph) return;
      var sec = ph.sections.find(function (s) { return s.id === secId; });
      if (!sec || !sec.items) return;
      sec.items.splice(idx, 1);
      room.updatedAt = Date.now();
      wrSetRooms(rooms);
      wrDbOpenRoom(roomId);
    };

    // ── 수치 행 ───────────────────────────────────────────────
    var _wrMetricTimers = {};
    window._wrMetricRowUpdate = function (roomId, phId, secId, ri, field, val) {
      var key = roomId + phId + secId + ri + field;
      clearTimeout(_wrMetricTimers[key]);
      _wrMetricTimers[key] = setTimeout(function () {
        var rooms = wrGetRooms();
        var room = rooms.find(function (r) { return r.id === roomId; });
        if (!room) return;
        var ph = room.phases && room.phases.find(function (p) { return p.id === phId; });
        if (!ph) return;
        var sec = ph.sections.find(function (s) { return s.id === secId; });
        if (!sec || !sec.rows) return;
        if (sec.rows[ri]) sec.rows[ri][field] = val;
        room.updatedAt = Date.now();
        wrSetRooms(rooms);
        // ✅ 저장 피드백: 해당 입력 테두리를 잠깐 초록으로
        var inputs = document.querySelectorAll('#wrSec_' + roomId + '_' + phId + '_' + secId + ' input');
        inputs.forEach(function (inp) {
          inp.style.borderBottomColor = '#4ade80';
          setTimeout(function () { inp.style.borderBottomColor = 'var(--b1)'; }, 600);
        });
      }, 500);
    };
    window._wrMetricRowAdd = function (roomId, phId, secId) {
      var rooms = wrGetRooms();
      var room = rooms.find(function (r) { return r.id === roomId; });
      if (!room) return;
      var ph = room.phases && room.phases.find(function (p) { return p.id === phId; });
      if (!ph) return;
      var sec = ph.sections.find(function (s) { return s.id === secId; });
      if (!sec) return;
      if (!sec.rows) sec.rows = [];
      sec.rows.push({ k: '', v: '' });
      room.updatedAt = Date.now();
      wrSetRooms(rooms);
      wrDbOpenRoom(roomId);
    };
    window._wrMetricRowDelete = function (roomId, phId, secId, ri) {
      var rooms = wrGetRooms();
      var room = rooms.find(function (r) { return r.id === roomId; });
      if (!room) return;
      var ph = room.phases && room.phases.find(function (p) { return p.id === phId; });
      if (!ph) return;
      var sec = ph.sections.find(function (s) { return s.id === secId; });
      if (!sec || !sec.rows) return;
      sec.rows.splice(ri, 1);
      wrSetRooms(rooms);
      wrDbOpenRoom(roomId);
    };

    // ── 날짜 기록 ────────────────────────────────────────────
    window._wrLogAdd = function (roomId, phId, secId) {
      var dateEl = document.getElementById('logDate_' + roomId + '_' + phId + '_' + secId);
      var textEl = document.getElementById('logText_' + roomId + '_' + phId + '_' + secId);
      var text = textEl && textEl.value.trim();
      if (!text) return;
      var rooms = wrGetRooms();
      var room = rooms.find(function (r) { return r.id === roomId; });
      if (!room) return;
      var ph = room.phases && room.phases.find(function (p) { return p.id === phId; });
      if (!ph) return;
      var sec = ph.sections.find(function (s) { return s.id === secId; });
      if (!sec) return;
      if (!sec.logs) sec.logs = [];
      sec.logs.unshift({ date: dateEl ? dateEl.value : '', text: text });
      room.updatedAt = Date.now();
      wrSetRooms(rooms);
      wrDbOpenRoom(roomId);
    };
    window._wrLogDelete = function (roomId, phId, secId, li) {
      var rooms = wrGetRooms();
      var room = rooms.find(function (r) { return r.id === roomId; });
      if (!room) return;
      var ph = room.phases && room.phases.find(function (p) { return p.id === phId; });
      if (!ph) return;
      var sec = ph.sections.find(function (s) { return s.id === secId; });
      if (!sec || !sec.logs) return;
      sec.logs.splice(li, 1);
      wrSetRooms(rooms);
      wrDbOpenRoom(roomId);
    };

    // ── 좌측 패널 리사이즈 ───────────────────────────────────
    (function () {
      var handle = document.getElementById('wrDbResizeHandle');
      var panel = document.getElementById('wrDbListPanel');
      if (!handle || !panel) return;
      var dragging = false, startX = 0, startW = 0;
      handle.addEventListener('mousedown', function (e) {
        dragging = true; startX = e.clientX; startW = panel.offsetWidth;
        handle.classList.add('dragging');
        document.body.style.userSelect = 'none';
        e.preventDefault();
      });
      document.addEventListener('mousemove', function (e) {
        if (!dragging) return;
        var w = Math.min(Math.max(startW + (e.clientX - startX), 160), 440);
        panel.style.width = w + 'px';
      });
      document.addEventListener('mouseup', function () {
        if (!dragging) return;
        dragging = false;
        handle.classList.remove('dragging');
        document.body.style.userSelect = '';
        localStorage.setItem('wr_list_panel_w', panel.style.width);
      });
      var saved = localStorage.getItem('wr_list_panel_w');
      if (saved) panel.style.width = saved;
    })();

    console.log('[v239-fix] 작업룸 버그수정 로드 완료 (wrDbUpdateName/Status/LinkItem 추가, _wrPhaseGet 저장 수정, 섹션ID 중복 해결, 일반매물 연결, 접기 DOM직접조작)');




